<template>
  <v-container>
    <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
    <v-card
    class="overflow-hidden"
    color="dark lighten-1"
    dark
  >
    <v-toolbar
      flat
      color="dark"
    >
      <v-icon>mdi-flag</v-icon>
      <v-toolbar-title class="font-weight-light">{{ $t('dashboard_pages_heading.settings') }}</v-toolbar-title>
      <v-spacer></v-spacer>
      <!-- <v-btn
        color="success"
        fab
        small
        @click="isEditing = !isEditing"
      >
        <v-icon v-if="isEditing">mdi-close</v-icon>
        <v-icon v-else>mdi-pencil</v-icon>
      </v-btn> -->
    </v-toolbar>
    <v-card-text v-if="alert.display == 'dialog' || alert.display == 'dataTable'">
      <BaseAlert/>
    </v-card-text>
    <v-card-text>
      <v-row>
        <!-- <v-col cols="12" md="4" sm="4" class="mx-auto">
          <v-select
            :items="lang.langs"
            :label="$t('dashboard_input_labels.select_language')"
            prepend-icon="mdi-flag"
            item-text="name"
            item-value="locale"
            dense
            v-model="translation.locale"
            @change="setTranslations"
            ></v-select>
        </v-col> -->
      </v-row>
    </v-card-text>
    <v-card-text>


        <v-expansion-panels focusable light class="my-5">
            <v-expansion-panel
              v-if="setting.settings.payment"
            >
            <v-expansion-panel-header style="text-transform:capitalize">{{ $t('settings_page.payment') }}</v-expansion-panel-header>
            <v-expansion-panel-content>
                <v-switch
                  :label="$t('dashboard_input_labels.stripe_enable')"
                  v-model="setting.settings.payment.stripe"
                >
                </v-switch>
                <v-switch
                  :label="$t('dashboard_input_labels.paypal_enable')"
                  v-model="setting.settings.payment.paypal"
                >
                </v-switch>
            </v-expansion-panel-content>
            </v-expansion-panel>
        </v-expansion-panels>

    </v-card-text>
    <v-divider></v-divider>
    <v-card-actions>
      <v-spacer></v-spacer>
      <v-btn
        color="success"
        @click="save"
        :disabled="!validForm && !isEditing" 
        :loading="setting.loadingBtn"
      >
        {{ $t('dashboard_modal.update_btn') }}
      </v-btn>
    </v-card-actions>
  </v-card>
  </v-form>
  </v-container>
</template>


<script>
  import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: () => ({
      isEditing:false,
      search:'',
      updatePassword:false,
      updateRole:false,
      validForm:false,
      singleSelect:false,
      selected:[],
    }),
    computed: {
      ...mapState(['setting' , 'alert', 'auth', 'lang']),
    },
    mixins:[formValidations],

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('setting', ['fetchSettings', 'updateSettings']),
      // initialize the data table
      async initialize () {
        this.fetchSettings()
      },
      // submit the form
      async save () {
        await this.updateSettings()
        this.$refs.modalForm.resetValidation()
      },
    },
    filters:{
      removeDash(value){
        if(value){
          return value.replace(/\_/g, ' ');
        }
      }
    }
  }
</script>