<template>
<div class="auth-layout primary">
    <v-container
        class="fill-height py-0"
        fluid
    >
        <v-row
            align="center"
            justify="center"
            class="auth-layout-row"
        >
            <v-col cols="10" class="mx-auto white dark--text">
                <v-row class="auth-row" align="center" justify="center">
                    <v-col cols="6" class="img-col d-none d-sm-block">
                        <!-- <v-card> -->
                            <v-img 
                                class="auth-img"
                                :src="getImage('login')"
                            ></v-img>
                        <!-- </v-card> -->
                    </v-col>
                    <v-col class="px-10 form-col">
                        <v-form @submit.prevent="submitForm" v-model="validForm">
                            
                                <div class="text-center my-5 form-header">{{ $t('auth_page.login_page_heading') }}</div>
                                
                                <div class="my-3">
                                    <CustomAlert :alert="alert"/>
                                </div>
                                
                                    <v-text-field
                                        class="auth-input"
                                        id="email"
                                        :label="$t('auth_page.email_label')"
                                        v-model="email"
                                        prepend-icon="mdi-email"
                                        type="email"
                                        :rules="emailRules"
                                        rounded
                                        solo
                                    />
                                    <v-text-field
                                        class="auth-input"
                                        id="password"
                                        :label="$t('auth_page.password_label')"
                                        v-model="password"
                                        prepend-icon="mdi-lock"
                                        :append-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
                                        @click:append="showPassword = !showPassword"
                                        :type="showPassword ? 'text' : 'password'"
                                        :rules="passwordRules"
                                        rounded
                                        solo
                                    />
                                
                                    <v-btn block rounded type="submit" color="primary" :disabled="!validForm" :dark="validForm" :loading="loading">
                                        {{ $t('auth_page.login') }}
                                    </v-btn>
                                    <v-divider class="my-5"></v-divider>
                                    <div class="text-center mb-5">
                                        <div>
                                            <small><router-link :to="{name: 'forgotPassword'}">{{ $t('auth_page.forgot_password_link') }}</router-link></small>
                                        </div>
                                        <div>
                                            <small><router-link :to="{ name: 'register' }">{{ $t('auth_page.create_account_link') }}</router-link></small>
                                        </div>
                                        <div>
                                            <small><router-link :to="{ name: 'products' }">{{ $t('auth_page.go_back_to_shoping_link') }}</router-link></small>
                                        </div>
                                    </div>
                                   
                                    
                               
                        </v-form>
                    </v-col>
                </v-row>
            </v-col>
      </v-row>


  </v-container>
  </div>
</template>

<script>
import auth from '@/mixins/auth'
import { mapGetters } from 'vuex'
export default {
    mixins:[auth],
    data(){
        return {
            validForm:false,
            name:'',
            email:'',
            password:'',
            showPassword:false,
            nameRules:[
                value => !!value || 'Please Type Your Name'
            ],
            emailRules:[
                value => !!value || 'Please Type Your Email',
                value => /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/.test(value) || 'Please Add Valid Email'
            ],
            passwordRules:[
                value => !!value || 'Please Type Password'
            ]
        }
    },
    computed:{
        ...mapGetters('image', ['getImage'])
    },
    methods: {
        async submitForm(){
            try {
                this.loading = true
                this.alert.show = false
                this.alert = await this.login({
                    email:this.email,
                    password:this.password
                })
                this.loading = false
            } catch (error) {
                this.loading = false
            }
            
            
        }
    },
}
</script>

