import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        icons:[],
        icon:{
            icon:'',
            url:'',
            order:'',
        },
        defaultIcon:{
            icon:'',
            url:'',
            order:'',
        },
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,

    },
    getters:{
        getIcon: state => id => {
            return state.icons.filter(icon => icon._id == id)
        }
    },
    mutations:{
        SET_ICONS: (state, payload) => {
            state.icons = payload
        },
        SET_ICON: (state, payload) => {
            state.icon = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_ICON: (state) => {
            state.icon = Object.assign({}, state.defaultIcon)
        },
        SET_EDIT_ICON: (state,payload) => {
            state.icon = Object.assign({}, payload)
        }
    },
    actions:{
        // fetch all icons
        fetchIcons: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/icons')
                commit('SET_ICONS', data.data.icons)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add icons
        addIcon: async ({state ,dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/icons',state.icon)
                dispatch('alert/setAlert', {
                    text:'Icon added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_ICON')
                dispatch('fetchIcons')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete icon
        deleteIcon: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/icons/'+id)
                dispatch('alert/setAlert', {
                    text:'Icon deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchIcons')
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update icon
        updateIcon: async ({state , dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/icons/'+state.icon._id,state.icon)
                dispatch('alert/setAlert', {
                    text:'Icon updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_ICON')
                dispatch('fetchIcons')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit icon
        setEditIcon: ({commit}, payload) => {
            commit('SET_EDIT_ICON', payload)
        },
        // set default icon
        setDefaultIcon: ({commit}) => {
            commit('SET_DEFAULT_ICON')
        }
    }
}