import { mapMutations, mapActions } from "vuex";
import setToken from '../utils/SetToken';
import Axios from 'axios'

// set the axios api base url
Axios.defaults.baseURL = process.env.NODE_ENV == 'development' ? 'http://localhost:5000' : location.origin

export default {
    methods: {
        ...mapMutations('auth',['SET_USER']),
        ...mapActions('auth',['logout']),
        ...mapActions('cart',['setCart']),
        ...mapActions('lang',['setLang', 'fetchLangs']),
        ...mapActions('image',['fetchImages']),
        ...mapActions('setting',['fetchSettings']),
    },
    created() {
        // check user in local storage and set user if it exists
        let user = JSON.parse(localStorage.getItem('user'))
        if(user){
            this.SET_USER(user)
            setToken(user.token)
        }else{
            setToken(false)
        }
        // check cart in local storage and set cart if it exists
        this.setCart()
        // if error is 401 logout
        Axios.interceptors.response.use(
            response => response,
            error => {
                if(error.response.status == 401){
                    this.logout()
                }
                return Promise.reject(error)
            }
        )
    },
    mounted() {
        this.fetchLangs()
        this.fetchSettings()
        let language = JSON.parse(localStorage.getItem('lang'))
        if(language){
            this.setLang(language)
        }
        this.fetchImages()
    }
}