import setErr from '../../utils/ResponseError'
export default {
    namespaced:true,
    state:{
        timeout:5000,
        text:'',
        show:false,
        type:'success',
        color:'success'
    },
    getters:{},
    mutations:{
        // set snacbar
        SET_SNACKBAR: (state,payload) => {
            state.timeout = payload.timeout ? payload.timeout : 5000,
            state.text = payload.text,
            state.show = true
            state.type = payload.type ? payload.type : 'success'
        }
    },
    actions:{
        setSnackbar: ({commit},payload) => {
            if(payload.type){
                if(payload.type = 'error'){
                    payload.text = setErr(payload.text)
                }
            }
            commit('SET_SNACKBAR', payload)
        }
    }
}