import Axios from 'axios'
import router from '../../router'
export default {
    namespaced:true,
    state:{
        address:{
            address1:'',
            address2:'',
            country:'',
            state:'',
            city:'',
            zip:'',
            phone:''
        },
        loading:false,
        loadingBtn:false
    },
    getters:{},
    mutations:{
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
    },
    actions:{
        // payment with card
        payWithCard: async ({dispatch,commit,rootGetters}, payload) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = await Axios.post('/api/payments/card', payload)
                if(rootGetters['auth/isLoggedIn']){
                    const userId = rootGetters['auth/getAuthUser']._id
                    await Axios.delete('/api/cart/'+userId)
                }
                await dispatch('cart/emptyCart', null, {root:true})
                await dispatch('snackbar/setSnackbar', {
                    text:'Thanks for making the payment',
                    type:'success'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
                router.push({name:'success'})
            } catch (error) {
                console.log(error.response)
                await dispatch('snackbar/setSnackbar', {
                    text:'Sorry something went wrong',
                    type:'error'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
            }
        },
        // payment with card
        payWithCardDigital: async ({dispatch,commit,rootGetters}, payload) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = await Axios.post('/api/payments/card/Digital', payload)
                await dispatch('snackbar/setSnackbar', {
                    text:'Thanks for making the payment',
                    type:'success'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
                router.push({name:'success'})
            } catch (error) {
                console.log(error.response)
                await dispatch('snackbar/setSnackbar', {
                    text:'Sorry something went wrong',
                    type:'error'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
            }
        },
        // payment with paypal
        payWithPaypal: async ({dispatch,commit,rootGetters}, payload) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/payments/paypal', payload)
                await dispatch('snackbar/setSnackbar', {
                    text:'Thanks for making the payment',
                    type:'success'
                }, {root:true})
                if(rootGetters['auth/isLoggedIn']){
                    const userId = rootGetters['auth/getAuthUser']._id
                    await Axios.delete('/api/cart/'+userId)
                }
                await dispatch('cart/emptyCart', null, {root:true})
                commit('SET_BTN_LOADING', false)
                router.push({name:'success'})
            } catch (error) {
                await dispatch('snackbar/setSnackbar', {
                    text:'Sorry something went wrong',
                    type:'error'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
            }
        },
        // payment with paypal digital
        payWithPaypalDigital: async ({dispatch,commit,rootGetters}, payload) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/payments/paypal/digital', payload)
                await dispatch('snackbar/setSnackbar', {
                    text:'Thanks for making the payment',
                    type:'success'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
                router.push({name:'success'})
            } catch (error) {
                await dispatch('snackbar/setSnackbar', {
                    text:'Sorry something went wrong',
                    type:'error'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
            }
        }
    }
}