import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        orders:[],
        order:{
            status:''
        },
        defaultOrder:{
            status:''
        },
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,

    },
    getters:{
        getOrder: state => id => {
            return state.orders.filter(order => order._id == id)
        }
    },
    mutations:{
        SET_ORDERS: (state, payload) => {
            state.orders = payload
        },
        SET_ORDER: (state, payload) => {
            state.order = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_ORDER: (state) => {
            state.order = Object.assign({}, state.defaultOrder)
        },
        SET_EDIT_ORDER: (state,payload) => {
            state.order = Object.assign({}, payload)
        }
    },
    actions:{
        // fetch all orders
        fetchOrders: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/orders')
                commit('SET_ORDERS', data.data.data)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // fetch single order
        fetchOrder: async ({dispatch,commit}, id) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/orders/'+id)
                commit('SET_ORDER', data.data.order)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add Order
        addOrder: async ({state ,dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                const data = await Axios.post('/api/orders',state.order)
                dispatch('alert/setAlert', {
                    text:'Order added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_ORDER')
                dispatch('fetchOrders')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete order
        deleteOrder: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/orders/'+id)
                dispatch('alert/setAlert', {
                    text:'Order deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchOrders')
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update order
        updateOrder: async ({state , dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/orders/'+state.order._id, state.order)
                dispatch('alert/setAlert', {
                    text:'Order updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                dispatch('fetchOrders')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit order
        setEditOrder: ({commit}, payload) => {
            commit('SET_EDIT_ORDER', payload)
        },
        // set default order
        setDefaultOrder: ({commit}) => {
            commit('SET_DEFAULT_ORDER')
        }
    }
}