<template>
  <v-container>
    <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="user.users"
          :search="search"
          :loading="user.loading"
          item-key="_id"
          :single-select="singleSelect"
          
          sort-by="name"
          class="elevation-1"
        >
          <template v-slot:top>
            <v-toolbar color="light">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.users') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog v-model="user.dialog" max-width="500px">
                <v-card>
                  <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
                    <v-card-title>
                      <span class="headline">
                        {{
                           !user.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.user') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.user') 
                        }}
                        </span>
                    </v-card-title>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                              <v-text-field
                                  :label="$t('dashboard_input_labels.name')"
                                  v-model="user.user.name"
                                  prepend-icon="mdi-account"
                                  type="text"
                                  :rules="[rules.required]"
                                  name="name"
                              />
                              <v-text-field
                                  id="email"
                                  :label="$t('dashboard_input_labels.email')"
                                  name="email"
                                  v-model="user.user.email"
                                  prepend-icon="mdi-email"
                                  type="email"
                                  :rules="[rules.required , rules.email]"
                              />
                              <v-select
                                :items="roles"
                                :label="$t('dashboard_input_labels.role')"
                                prepend-icon="mdi-account"
                                name="role"
                                dense
                                :rules="[rules.required]"
                                v-model="user.user.role"
                              ></v-select>
                              <v-switch
                                v-if="user.edit"
                                v-model="updatePassword"
                                :label="$t('dashboard_input_labels.update_password')"
                              ></v-switch>
                              <v-text-field
                                  id="password"
                                  counter
                                  :label="$t('dashboard_input_labels.password')"
                                  name="password"
                                  v-model="user.user.password"
                                  prepend-icon="mdi-lock"
                                  :append-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
                                  @click:append="showPassword = !showPassword"
                                  :type="showPassword ? 'text' : 'password'"
                                  :rules="[rules.required , rules.minLength]"
                                  v-if="!user.edit || updatePassword"
                              />
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="user.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
  import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      search:'',
      updatePassword:false,
      validForm:false,
      singleSelect:false,
      selected:[],
      showPassword:false,
      roles:['user', 'publisher', 'admin'],
      headers: [
        {
          text: vm.$t('dashboard_datatable.name'),
          align: 'start',
          value: 'name',
        },
        { text: vm.$t('dashboard_datatable.email'), value: 'email' },
        { text: vm.$t('dashboard_datatable.role'), value: 'role' },
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ]
    }),
    computed: {
      ...mapState(['user' , 'alert']),
      ...mapGetters('user',['getUser'])

    },
    mixins:[formValidations],

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('user', ['fetchUsers', 'addUser', 'setDialog', 'deleteUser', 'updateUser', 'setEditUser', 'setDefaultUser']),
      // initialize the data table
      async initialize () {
        await this.fetchUsers()
      },
      // edit item
      async editItem (item) {
        this.setEditUser(item)
        this.setDialog({dialog:true,edit:true})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // delete item
      async deleteItem (item) {
        if(confirm('Are you sure you want to delete this user?')){
          await this.deleteUser(item._id)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.$refs.modalForm.reset()
        this.setDefaultUser()
        this.setDialog({dialog:false,edit:false})
      },
      // submit the form
      async save () {
        if (this.user.edit) {
          await this.updateUser()
        } else {  
          await this.addUser()
        }
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>