import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        reports:{
            dayReport: {
                totalAmount: 0,
                totalOrders: 0,
                totalSales:0,
            },
            weekReport: {
                totalAmount: 0,
                totalOrders: 0,
                totalSales:0,
            },
            monthReport: {
                totalAmount: 0,
                totalOrders: 0,
                totalSales:0,
            },
            yearReport: {
                totalAmount: 0,
                totalOrders: 0,
                totalSales:0,
            }
        },
        records:{
            yearRecords:null
        },
        report:{},
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,
        count:0
    },
    getters:{
        getOrder: state => id => {
            return state.orders.filter(order => order._id == id)
        }
    },
    mutations:{
        SET_REPORTS: (state, payload) => {
            state.reports = payload
        },
        SET_RECORDS: (state, payload) => {
            state.records = payload
        },
        SET_REPORT: (state, payload) => {
            state.report = payload
        },
        SET_COUNT: (state, payload) => {
            state.count = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        }
    },
    actions:{
        // fetch Reports
        fetchReports: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/orders/getReports')
                commit('SET_REPORTS', data.data.reports)
                commit('SET_RECORDS', data.data.records)
                commit('SET_COUNT', data.data.totalOrders)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        }
    }
}