<template>
  <div v-if="alert.show">
    <v-alert
      dense
      text
      :type="alert.type"
      dismissible
      v-model="alert.show"
    >
      {{ alert.text }}
    </v-alert>
  </div>
</template>

<script>
import { mapState, mapActions } from 'vuex'
export default {
  data(){
    return {

    }
  },
  computed: {
    ...mapState(['alert'])
  },
  methods: {
    ...mapActions('alert', ['removeAlert'])
  },
}
</script>