<template>
  <v-carousel
    cycle
    height="400"
    hide-delimiter-background
    show-arrows-on-hover
  >
    <v-carousel-item
      v-for="(slider, i) in slider.sliders"
      :key="i"
      :src="setting.settings.images.url+'/sliders/'+slider.image"
    >
      <v-overlay
        absolute
        :opacity="0"
        height="100%"
      >
        <v-row
          class="fill-height"
          align="center"
          justify="center"
        >
          <div class="display-3">{{ slider.heading }}</div>
        </v-row>
      </v-overlay>
    </v-carousel-item>
  </v-carousel>
</template>

<script>
  import { mapState, mapActions } from 'vuex'
  export default {
    data(){
      return {
        path:process.env.VUE_APP_URL+'/uploads/sliders/',
      }
    },
    computed:{
      ...mapState(['slider','setting'])
    },
    methods:{
      ...mapActions('slider', ['fetchSliders'])
    },
    mounted(){
      this.fetchSliders()
    }
  }
</script>