<template>
  <v-container>
    <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="product.products"
          :search="search"
          :loading="product.loading"
          item-key="_id"
          :single-select="singleSelect"
          show-expand
          sort-by="date"
          sort-desc
          class="elevation-1"
        >

        <!-- Expandable Template -->
        <template v-slot:expanded-item="{ headers, item }">
          <v-img max-width="500" :src="path+item.avatar"></v-img>      
        </template>
        <!-- Category Template -->
        <template v-slot:expanded-item="{ headers, item }">
          <v-img max-width="500" :src="path+item.avatar"></v-img>      
        </template>
          <template v-slot:top>
            <v-toolbar color="light">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.products') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog :focus="false" class="product-dialog" v-model="product.dialog" fullscreen>
                <v-card>
                  <v-form ref="modalForm" id="productForm" @submit.prevent="save" v-model="validForm" enctype="multipart/form-data">
                    <v-toolbar dark color="dark">
                      <v-toolbar-title class="mx-auto">
                        <span class="headline">
                          {{
                           !product.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.product') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.product') 
                        }}
                        </span>
                      </v-toolbar-title>
                    </v-toolbar>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                            <v-text-field
                              :label="$t('dashboard_input_labels.name')"
                              v-model="product.product.name"
                              prepend-icon="mdi-shopping"
                              type="text"
                              :rules="[rules.required]"
                              name="name"
                            />
                            <v-select
                              :items="cat.cats"
                              :label="$t('dashboard_input_labels.category')"
                              item-text="name"
                              item-value="_id"
                              prepend-icon="mdi-shape"
                              name="category"
                              dense
                              :rules="[rules.required]"
                              v-model="product.product.category"
                            ></v-select>
                            <v-textarea
                              counter
                              :label="$t('dashboard_input_labels.excerpt')"
                              :rules="[rules.required]"
                              v-model="product.product.excerpt"
                              prepend-icon="mdi-shape"
                            ></v-textarea>
                            <v-select
                              :items="types"
                              :label="$t('dashboard_input_labels.type')"
                              prepend-icon="mdi-shape"
                              :rules="[rules.required]"
                              v-model="product.product.type"
                            ></v-select>
                            <v-text-field
                              :disabled="product.product.type == 'physical'"
                              :label="$t('dashboard_input_labels.link')"
                              v-model="product.product.link"
                              prepend-icon="mdi-shape"
                              type="text"
                            />
                            <v-text-field
                              :label="$t('dashboard_input_labels.price')"
                              v-model="product.product.price"
                              prepend-icon="mdi-shape"
                              type="number"
                              :rules="[rules.required]"
                              name="price"
                            />
                            <v-file-input
                              v-model="product.product.avatar"
                              append-icon="mdi-camera"
                              :label="product.edit ? $t('dashboard_input_labels.update_image') : $t('dashboard_input_labels.image')"
                              :rules="product.edit? [rules.image,rules.imageSize] : [rules.image,rules.imageSize,rules.required]"
                              @change="uploadImage"
                            >
                            </v-file-input>
                            <v-img
                              v-if="product.avatarUrl"
                              :src="product.avatarUrl"
                            ></v-img>
                            <vue-ckeditor 
                            class="product-editor"
                              v-model="product.product.description" 
                              :config="config" 
                              @blur="onBlur($event)" 
                              @focus="onFocus($event)"
                              @contentDom="onContentDom($event)"
                              @dialogDefinition="onDialogDefinition($event)"
                              @fileUploadRequest="onFileUploadRequest($event)"
                              @fileUploadResponse="onFileUploadResponse($event)" />
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="product.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
// import ClassicEditor from '@ckeditor/ckeditor5-build-classic';
import VueCkeditor from 'vue-ckeditor2';
import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      config: {
        toolbar: [
          { name: 'document', items: [ 'Source', '-', 'Save', 'NewPage', 'Preview', 'Print', '-', 'Templates' ] },
          { name: 'clipboard', items: [ 'Cut', 'Copy', 'Paste', 'PasteText', 'PasteFromWord', '-', 'Undo', 'Redo' ] },
          { name: 'editing', items: [ 'Find', 'Replace', '-', 'SelectAll', '-', 'Scayt' ] },
          { name: 'forms', items: [ 'Form', 'Checkbox', 'Radio', 'TextField', 'Textarea', 'Select', 'Button', 'ImageButton', 'HiddenField' ] },
          '/',
          { name: 'basicstyles', items: [ 'Bold', 'Italic', 'Underline', 'Strike', 'Subscript', 'Superscript', '-', 'CopyFormatting', 'RemoveFormat' ] },
          { name: 'paragraph', items: [ 'NumberedList', 'BulletedList', '-', 'Outdent', 'Indent', '-', 'Blockquote', 'CreateDiv', '-', 'JustifyLeft', 'JustifyCenter', 'JustifyRight', 'JustifyBlock', '-', 'BidiLtr', 'BidiRtl', 'Language' ] },
          { name: 'links', items: [ 'Link', 'Unlink', 'Anchor' ] },
          { name: 'insert', items: [ 'Flash', 'Table', 'HorizontalRule', 'Smiley', 'SpecialChar', 'PageBreak', 'Iframe' ] },
          '/',
          { name: 'styles', items: [ 'Styles', 'Format', 'Font', 'FontSize' ] },
          { name: 'colors', items: [ 'TextColor', 'BGColor' ] },
          { name: 'tools', items: [ 'Maximize', 'ShowBlocks' ] },
          { name: 'about', items: [ 'About' ] }
        ],
        height: 300
      },
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      types:['physical','digital'],
      headers: [
        {
          text: vm.$t('dashboard_datatable.name'),
          align: 'start',
          value: 'name',
        },
        { text: vm.$t('dashboard_datatable.price'), value: 'price'},
        { text: vm.$t('dashboard_datatable.type'), value: 'type'},
        { text: vm.$t('dashboard_datatable.category'), value: 'category.name'},
        { text: vm.$t('dashboard_datatable.user'), value: 'user.name'},
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ],
    }),
    components: { 
      VueCkeditor 
    },
    mixins:[formValidations],
    computed: {
      ...mapState(['product' , 'alert', 'cat', 'auth', 'setting']),
      ...mapGetters('product',['getProduct']),
      path(){
        return this.setting.settings.images.url+'/products/'
      },
      description(){
        return this.product.product.description
      }
    },

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('product', ['fetchProducts', 'addProduct', 'setDialog', 'deleteProduct', 'updateProduct', 'setEditProduct', 'setDefaultProduct', 'uploadImage']),
      // initialize the data table
      async initialize () {
        let payload = {
          limit:1000
        }
        if(this.auth.user.role == 'publisher'){
          payload.user = this.auth.user._id
        }
        await this.fetchProducts(payload)
      },
      // edit item
      async editItem (item) {
        this.setDialog({dialog:true,edit:true})
        this.setEditProduct(item)
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // delete item
      async deleteItem (item) {
        const delItem = item._id
        if(confirm('Are you sure you want to delete this Product?')){
          await this.deleteProduct(delItem)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.setDefaultProduct()
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.setDialog({dialog:false,edit:false})
        this.setDefaultProduct()
        this.$refs.modalForm.resetValidation()
      },
      // submit the form
      async save () {
        if (this.product.edit) {
          await this.updateProduct()
        } else {  
          await this.addProduct()
        }
        this.$refs.modalForm.resetValidation()
      },

      onBlur(evt) {
      console.log(evt);
    },
    onFocus(evt) {
      console.log(evt);
    },
    onContentDom(evt) {
      console.log(evt);
    },
    onDialogDefinition(evt) {
      console.log(evt);
    },
    onFileUploadRequest(evt) {
      console.log(evt);
    },
    onFileUploadResponse(evt) {
      console.log(evt);
    }
    },
  }
</script>


<style lang="css">
  .product-editor{
    z-index: 100 !important;
  }
  .product-dialog{
    z-index: 90 !important;
  }
</style>