<template>
    <v-list two-line subheader>
        <v-list-item
            v-for="(product, index) in cart.products"
            :key="index"
        >
            <v-list-item-avatar>
            <v-img
                :src="url+product.avatar"
            ></v-img>
            </v-list-item-avatar>
            <v-list-item-content>
            <v-list-item-title v-text="product.name"></v-list-item-title>
            <v-list-item-subtitle>{{ $t('cart_page.quantity') }}: {{ product.quantity }}</v-list-item-subtitle>
            <v-list-item-subtitle>${{ product.quantity * product.price }}</v-list-item-subtitle>
            <v-list-item-subtitle>
                <v-btn
                    :disabled="product.quantity == 1" 
                    text
                    small 
                    @click="changeQty({productId:product._id, value:1, type:'decrease'})"
                >
                    <v-icon>mdi-minus</v-icon>
                </v-btn>
                <v-btn
                    text
                    small 
                    @click="changeQty({productId:product._id, value:1, type:'increase'})"
                >
                    <v-icon>mdi-plus</v-icon>
                </v-btn>
            </v-list-item-subtitle>
            </v-list-item-content>

            <v-list-item-action>
            <v-btn icon @click="removeProduct({index, productId:product._id})">
                <v-icon small color="grey lighten-1">mdi-close</v-icon>
            </v-btn>
            </v-list-item-action>
        </v-list-item>
    </v-list>
</template>

<script>
import { mapActions, mapState } from 'vuex'
export default {
    data(){
        return {
            url:this.$store.state.setting.settings.images.url+'/uploads/products/'
        }
    },
    computed: {
        ...mapState(['cart'])
    },
    methods: {
        ...mapActions('cart', ['removeProduct', 'changeQty'])
    },
}
</script>

<style scoped>
    .slide-leave-to{
        opacity: 0;
    }

    .slide-leave-active{
        transition: opacity 1s;
    }
</style>