<template>
  <v-container>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          hide-default-header
          :items="notification.notifications"
          :loading="notification.loading"
          item-key="_id"
          sort-by="-date"
          class="elevation-1"
        >
        <!-- Date Template -->
        <template v-slot:item.date="{ item }">
            <span>{{item.date | formatDate}}</span>
        </template>
        <template v-slot:item="{ item }">
            <v-container>
              <v-row>
                <v-col color="dark">
                  <v-card 
                    link 
                    :color="!item.read ? 'light darken-1' : 'light'"
                    @click="itemClicked(item._id,item.data)"
                    >
                    <v-card-text v-if="item.type == 'order'">
                      {{ $t('notifications.order') }}
                    </v-card-text>
                    <v-card-text>{{item.date | formatDate}}</v-card-text>
                  </v-card>
                </v-col>
              </v-row>
            </v-container>
        </template>
          <template v-slot:top>
            <v-toolbar color="primary" dark>
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.notifications') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <small
                    @click="readAllNotifications" 
                    class="mark-all-link"
                >{{ $t('notifications.mark_all_as_read') }}</small>
            </v-toolbar>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
  import moment from 'moment'
  import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      
    }),
    mixins:[formValidations],
    computed: {
      ...mapState(['notification' , 'alert'])
    },
    created () {
      this.initialize()
    },
    methods: {
      ...mapActions('notification', ['fetchNotifications', 'readNotification', 'readAllNotifications']),
      itemClicked(id,data){
          this.readNotification(id,data)
          this.$router.push({name:'dOrderDetails', params:{orderId:data}})
      },
      // initialize the data table
      async initialize () {
        await this.fetchNotifications()
      },
    },
    filters:{
        formatDate(value) {
            if (value) {
                return moment(String(value)).format('MM/DD/YYYY hh:mm')
            }
        }
    }
  }
</script>