<template>
  <v-col class="text-center my-5">
      <div class="text-center">
    <v-pagination
      v-model="page"
      :length="getPaginationLength"
      circle
      @input="next"
    ></v-pagination>
  </div>
  </v-col>
</template>

<script>
import { mapState, mapGetters, mapActions } from 'vuex'
  export default {
    data () {
      return {
        page:1,
        category:false
      }
    },
    computed:{
        ...mapState(['product']),
        ...mapGetters('product', ['getPaginationLength'])
    },
    created(){
        let query = this.$route.query
        this.category = query.category ? query.category : false
        this.page = query.page ? Number(query.page) : 1
    },
    methods:{
      next(){
        let query = {
          page:this.page
        }
        if(this.category){
          query.category = this.category
        }
        this.$router.push({name:'products', query})
      }
    }
  }
</script>