<script>
import { Bar } from 'vue-chartjs'
import { mapState } from 'vuex'
export default {
    data(){
        return {
            data:{},
            options:{}
        }
    },
    extends:Bar,
    computed:{
      ...mapState(['report'])
    },
    mounted(){
      this.renderChart({
        labels: this.report.records.yearRecords.months,
        datasets: [
          {
            label: this.$t('dashboard_page.annual_income_record'),
            backgroundColor: '#4e73df',
            data: this.report.records.yearRecords.amounts
          }
        ]
      })
    }
}
</script>

