<template>
  <v-container>
    <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="slider.sliders"
          :search="search"
          :loading="slider.loading"
          item-key="_id"
          :single-select="singleSelect"
          show-expand
          sort-by="order"
          class="elevation-1"
        >
        <!-- Expandable Template -->
        <template v-slot:expanded-item="{ headers, item }">
          <v-img max-width="500" :src="path+item.image"></v-img>      
        </template>
          <template v-slot:top>
            <v-toolbar color="light">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.slider') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog v-model="slider.dialog" max-width="500px">
                <v-card>
                  <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
                    <v-card-title>
                      <span class="headline">
                        {{
                           !slider.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.slider') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.slider') 
                        }}
                      </span>
                    </v-card-title>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                              <v-text-field
                                  :label="$t('dashboard_input_labels.heading')"
                                  v-model="slider.slider.heading"
                                  prepend-icon="mdi-shape"
                                  type="text"
                                  :rules="[rules.required]"
                              />
                              <v-text-field
                                  :label="$t('dashboard_input_labels.order')"
                                  v-model="slider.slider.order"
                                  prepend-icon="mdi-shape"
                                  type="number"
                                  :rules="[rules.required]"
                              />
                              <v-file-input
                                  v-model="slider.slider.image"
                                  append-icon="mdi-camera"
                                  :label="slider.edit ? $t('dashboard_input_labels.update_image') : $t('dashboard_input_labels.image')"
                                  :rules="slider.edit? [rules.image,rules.imageSize] : [rules.image,rules.imageSize,rules.required]"
                                  @change="uploadImage"
                              >
                              </v-file-input>
                              <v-img
                                    v-if="slider.imageUrl"
                                    :src="slider.imageUrl"
                              ></v-img>
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="slider.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      headers: [
        {
          text: vm.$t('dashboard_datatable.heading'),
          align: 'start',
          value: 'heading',
        },
        { text: vm.$t('dashboard_datatable.order'), value: 'order' },
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ],
    }),
    mixins:[formValidations],
    computed: {
      ...mapState(['slider' , 'alert', 'setting']),
      ...mapGetters('slider',['getSlider']),
      path(){
        return this.setting.settings.images.url+'/sliders/'
      }
    },

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('slider', ['fetchSliders', 'addSlider', 'setDialog', 'deleteSlider', 'updateSlider', 'setEditSlider', 'setDefaultSlider', 'uploadImage']),
      // initialize the data table
      async initialize () {
        await this.fetchSliders()
      },
      // edit item
      async editItem (item) {
        this.setEditSlider(item)
        this.setDialog({dialog:true,edit:true})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // delete item
      async deleteItem (item) {
        const delItem = item._id
        if(confirm('Are you sure you want to delete this Slider?')){
          await this.deleteSlider(delItem)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.setDefaultSlider()
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.setDialog({dialog:false,edit:false})
        this.setDefaultSlider()
        this.$refs.modalForm.resetValidation()
      },
      // submit the form
      async save () {
        if (this.slider.edit) {
          await this.updateSlider()
        } else {  
          await this.addSlider()
        }
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>

