<template>
          <v-col cols="12" md="4" sm="6">
            <v-card
            >
                <v-img
                v-if="product.avatar"
                height="250"
                :src="setting.settings.images.url+'/products/'+product.avatar"
                ></v-img>

                <v-card-title>
                    <router-link :to="{name:'singleProduct', params:{productId:product._id}}">
                        {{ product.name }}
                    </router-link>
                </v-card-title>

                <v-card-text>
                <v-row
                    align="center"
                    class="mx-0"
                >
                    <v-rating
                        :value="productRating(product.reviews)"
                        color="amber"
                        dense
                        half-increments
                        readonly
                        size="14"
                    ></v-rating>

                    <div class="grey--text ml-4">{{ productRating(product.reviews) }} ({{ productReviewsCount(product.reviews) }})</div>
                </v-row>
                <div class="my-4 subtitle-1">
                    <h3 right class="mr-3 primary--text">${{ product.price }}</h3>
                </div>

                <div>
                    {{ product.excerpt }}
                </div>
                </v-card-text>

                <v-divider class="mx-4"></v-divider>
                <v-card-actions>
                    <v-btn v-if="product.type == 'physical'" @click="addProductToCart" class="mx-auto" color="success" dark>
                        {{ $t('products_page.add_to_cart') }}
                        <v-icon>mdi-cart</v-icon>
                    </v-btn>
                    <v-btn v-if="product.type == 'digital'" @click="goToBuy(product._id)" class="mx-auto" color="success" dark>
                        {{ $t('products_page.buy_now') }}
                        <v-icon>mdi-cash-usd</v-icon>
                    </v-btn>
                </v-card-actions>
            </v-card>
            <v-dialog
            v-model="dialog"
            max-width="290"
            >
            <v-card>
                <v-card-title class="headline">{{ $t('products_page.modal_heading') }}</v-card-title>

                <v-card-text>
                    {{ $t('products_page.modal_text') }}
                </v-card-text>

                <v-card-actions>
                <v-spacer></v-spacer>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'register'}"
                >
                    {{ $t('products_page.modal_register') }}
                </v-btn>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'login'}"
                >
                    {{ $t('products_page.modal_login') }}
                </v-btn>
                </v-card-actions>
            </v-card>
            </v-dialog>
          </v-col>
</template>

<script>
import Loading from '@/components/Loading/Loading'
import { mapActions, mapState, mapGetters } from 'vuex'
export default {
    props:{
        product:{
            type:Object
        }
    },
    data(){
        return {
            dialog:false
        }
    },
    methods: {
        ...mapActions('cart', ['addProduct']),
        addProductToCart(){
            this.addProduct(this.product)
        },
        goToBuy(id){
            if(!this.isLoggedIn){
                this.dialog = true
            }else{
                this.$router.push({name:'digitalCheckout', params:{productId:id}})
            }
        }
    },
    computed: {
        ...mapState(['setting', 'auth']),
        ...mapGetters('auth', ['isLoggedIn']),
        ...mapGetters('product', ['productRating', 'productReviewsCount'])
    },
    components:{
        Loading
    }
}
</script>

