<template>
  <v-container>
    <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
    <v-card
    class="overflow-hidden"
    color="primary lighten-1"
    dark
  >
    <v-toolbar
      flat
      color="primary"
    >
      <v-icon>mdi-cart-outline</v-icon>
      <v-toolbar-title class="font-weight-light">{{ $t('dashboard_pages_heading.order_details') }}</v-toolbar-title>
      <v-spacer></v-spacer>
    </v-toolbar>
    <v-card-text v-if="alert.display == 'dialog' || alert.display == 'dataTable'">
      <BaseAlert/>
    </v-card-text>
    <v-card-text>
      <v-row>
        <v-col cols="10" class="mx-auto">
            <div>{{ $t('order_details_page.product_details') }}</div>
            <OrderProducts :products="order.order.products"/>
        </v-col>
      </v-row>
    </v-card-text>
    <v-card-text>
      <v-row>
        <v-col cols="10" class="mx-auto" v-if="order.order.type == 'physical'">
            <div>{{ $t('order_details_page.delivery_details') }}</div>
            <DeliveryAddress :address="order.order.address"/>
        </v-col>
      </v-row>
    </v-card-text>
    <v-card-text>
      <v-row>
        <v-col cols="10" class="mx-auto">
            <div>{{ $t('order_details_page.user_details') }}</div>
            <UserDetails :user="order.order.user"/>
        </v-col>
      </v-row>
    </v-card-text>
    <v-card-text>
      <v-row>
        <v-col cols="10" class="mx-auto">
            <div>{{ $t('order_details_page.other_details') }}</div>
            <OrderDetails :amount="order.order.amount" :status="order.order.status"/>
        </v-col>
      </v-row>
    </v-card-text>
    <v-card-text>
      <v-row>
          <v-col cols="12" md="4" class="mx-auto">
              <v-select
                    :items="status"
                    :label="$t('dashboard_input_labels.status')"
                    prepend-icon="mdi-shape"
                    dense
                    v-model="order.order.status"
                    @change="save"
                ></v-select>
          </v-col>
      </v-row>
    </v-card-text>
    <v-divider></v-divider>
    <!-- <v-card-actions>
      <v-spacer></v-spacer>
      <v-btn
        color="success"
        @click="save"
        :disabled="!validForm && !isEditing" 
        :loading="order.loadingBtn"
      >
      {{ $t('dashboard_modal.update_btn') }}
      </v-btn>
    </v-card-actions> -->
  </v-card>
  </v-form>
  </v-container>
</template>


<script>
  import formValidations from '@/mixins/formValidations'
  import OrderProducts from '@/components/dashboard/order/OrderProducts'
  import DeliveryAddress from '@/components/dashboard/order/DeliveryAddress'
  import UserDetails from '@/components/dashboard/order/UserDetails'
  import OrderDetails from '@/components/dashboard/order/OrderDetails'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: () => ({
      isEditing:false,
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      status:['recieved', 'processing', 'delivered'],
    }),
    computed: {
      ...mapState(['order' , 'alert', 'auth']),
    },
    mixins:[formValidations],

    created () {
      this.initialize()
    },
    components:{
        OrderProducts,
        DeliveryAddress,
        UserDetails,
        OrderDetails
    },
    methods: {
      ...mapActions('order', ['fetchOrder', 'updateOrder']),
      // initialize the data table
      async initialize () {
        await this.fetchOrder(this.$route.params.orderId)
      },
      // submit the form
      async save () {
        await this.updateOrder()
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>