import setErr from '../../utils/ResponseError'
export default {
    namespaced:true,
    state:{
        timeout:null,
        text:'',
        show:false,
        type:'success',
        display:''
    },
    getters:{},
    mutations:{
        // set alert
        SET_ALERT: (state,payload) => {
            // set alert with default options if options are not provided
            state.timeout = payload.timeout ? payload.timeout : null,
            state.text = payload.text,
            state.show = true
            state.type = payload.type ? payload.type : 'success'
            state.display = payload.display ? payload.display : ''
        },
        // remove alert
        REMOVE_ALERT : (state) => {
            // set back to default to remove alert from view
            state.timeout = null
            state.text = '',
            state.show = false
            state.type = 'success'
            state.display = ''
        }
    },
    actions:{
        // set alert action
        setAlert: ({commit},payload) => {
            // check for payload type success or error
            // if type is success then display the success message straight
            // if type is error then set error from response from backend api in setErr function
            if(payload.type){
                if(payload.type == 'error'){
                    payload.text = setErr(payload.text)
                }
            }
            // set alert commit
            commit('SET_ALERT', payload)
            // if payload timeout is set remove the alert after that timeout
            // if payload timeout is not set then display the alert continously
            if(payload.timeout){
                setTimeout(() => {
                    // remove alert commit
                    commit('REMOVE_ALERT')
                }, payload.timeout);
            }
        },
        // remove alert action
        removeAlert: ({commit}) => {
            // remove alert commit
            commit('REMOVE_ALERT')
        }
    }
}