<template>
  <div>
        <div v-if="!product.loading">
          <v-row v-if="product.product">
            <Product/>
          </v-row>
          <div>
            <Reviews/>
          </div>
        </div>
        <div v-else class="text-center my-5">
          <Loading />
        </div>
     
  </div>
</template>

<script>

import { mapActions, mapState } from 'vuex'
import Product from '@/components/pages/products/Product'
import Reviews from '@/components/pages/products/Reviews'
import Loading from '@/components/Loading/Loading4'

export default {
  components:{
    Product,
    Reviews,
    Loading
  },
  computed: {
    ...mapState(['product'])
  },
  methods: {
    ...mapActions('product', ['fetchProduct']),
  },
  async mounted() {
    await this.fetchProduct(this.$route.params.productId)
  },
}
</script>

