<template>
  <v-container>
    <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="image.images"
          :search="search"
          :loading="image.loading"
          item-key="_id"
          :single-select="singleSelect"
          sort-by="name"
          class="elevation-1"
          show-expand
        >
        <!-- Expandable Template -->
        <template v-slot:item.image="{ headers, item }">
          <v-img max-width="100" class="my-3" :src="path+item.image"></v-img>      
        </template>
        <template v-slot:expanded-item="{ headers, item }">
          <v-img max-width="500" :src="path+item.image"></v-img>      
        </template>
          <template v-slot:top>
            <v-toolbar color="light">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.images') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog v-model="image.dialog" max-width="500px">
                <v-card>
                  <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
                    <v-card-title>
                      <span class="headline">
                        {{
                           !image.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.image') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.image') 
                        }}
                      </span>
                    </v-card-title>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                              <v-select
                                :items="selectImages"
                                :label="$t('dashboard_input_labels.type')"
                                prepend-icon="mdi-shape"
                                dense
                                :rules="[rules.required]"
                                v-model="image.image.type"
                              ></v-select>
                              <v-file-input
                                  v-model="image.image.image"
                                  append-icon="mdi-camera"
                                  :label="image.edit ? $t('dashboard_input_labels.update_image') : $t('dashboard_input_labels.image')"
                                  :rules="image.edit? [rules.image,rules.imageSize] : [rules.image,rules.imageSize,rules.required]"
                                  @change="uploadImage"
                              >
                              </v-file-input>
                              <v-img
                                    v-if="image.imageUrl"
                                    :src="image.imageUrl"
                              ></v-img>
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="image.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      path:vm.$store.state.setting.settings.images.url+'/images/',
      selectImages:['login', 'register', 'update password', 'forgot password'],
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      headers: [
        {
          text: vm.$t('dashboard_datatable.type'),
          align: 'start',
          value: 'type',
        },
        { text: vm.$t('dashboard_datatable.image'), value: 'image' },
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ],
    }),
    mixins:[formValidations],
    computed: {
      ...mapState(['image' , 'alert']),
      ...mapGetters('image',['getImage'])
    },

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('image', ['fetchImages', 'addImage', 'setDialog', 'deleteImage', 'updateImage', 'setEditImage', 'setDefaultImage', 'uploadImage']),
      // initialize the data table
      async initialize () {
        await this.fetchImages()
      },
      // edit item
      async editItem (item) {
          console.log(item)
        this.setEditImage(item)
        this.setDialog({dialog:true,edit:true})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // delete item
      async deleteItem (item) {
        const delItem = item._id
        if(confirm('Are you sure you want to delete this Image?')){
          await this.deleteImage(delItem)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.setDefaultImage()
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.setDialog({dialog:false,edit:false})
        this.setDefaultImage()
        this.$refs.modalForm.resetValidation()
      },
      // submit the form
      async save () {
        if (this.image.edit) {
          await this.updateImage()
        } else {  
          await this.addImage()
        }
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>