import Vue from 'vue'
import VueRouter from 'vue-router'
import Nprogress from 'nprogress'

// load components
import PagesLayout from '@/views/layouts/PagesLayout'
import Index from '@/views/pages/Index'
import Products from '@/views/pages/Products'
import Product from '@/views/pages/Product'
import Cart from '@/views/pages/Cart'
import Checkout from '@/views/pages/Checkout'
import DigitalCheckout from '@/views/pages/DigitalCheckout'
import Success from '@/views/pages/Success'
import Auth from '@/views/pages/Auth'
import Login from '@/views/pages/auth/Login'
import Register from '@/views/pages/auth/Register'
import ForgotPassword from '@/views/pages/auth/ForgotPassword'
import UpdatePassword from '@/views/pages/auth/UpdatePassword'

// Dashboard Components
import DashboardLayout from '@/views/layouts/DashboardLayout'
import Dashboard from '@/views/dashboard/Dashboard'
import DProducts from '@/views/dashboard/Products'
import DCategories from '@/views/dashboard/Categories'
import DProfile from '@/views/dashboard/Profile'
import DUsers from '@/views/dashboard/Users'
import DOrders from '@/views/dashboard/Orders'
import DOrderDetails from '@/views/dashboard/OrderDetails'
import DSliders from '@/views/dashboard/Sliders'
import DImages from '@/views/dashboard/Images'
import DIcons from '@/views/dashboard/Icons'
import DLangs from '@/views/dashboard/Langs'
import DTranslations from '@/views/dashboard/Translations'
import DSettings from '@/views/dashboard/Settings'
import DNotifications from '@/views/dashboard/Notifications'

// import store
import store from '../store'


Vue.use(VueRouter)

const routes = [
    // index path
    {
        path:'/',
        name:'pageslayout',
        component:PagesLayout,
        redirect:{name: 'products'},
        children:[
            {
                path:'/home',
                name:'index',
                component:Index,
                meta:{
                    sidebar:false
                },
            },
            {
                path:'/Index',
                name:'products',
                component:Products,
            },
            {
                path:'/Products/:productId',
                name:'singleProduct',
                component:Product,
            },
            {
                path:'/cart',
                name:'cart',
                component:Cart,
                meta:{
                    sidebar:false
                }
            },
            {
                path:'/checkout',
                name:'checkout',
                component:Checkout,
                meta:{
                    isLoggedIn:true,
                    sidebar:false
                }
            },
            {
                path:'/service/checkout/:productId',
                name:'digitalCheckout',
                component:DigitalCheckout,
                meta:{
                    isLoggedIn:true,
                    sidebar:false
                }
            },
            {
                path:'/success',
                name:'success',
                component:Success,
                meta:{
                    isLoggedIn:true,
                    sidebar:false
                }
            },
            // auth path
            {
                path:'/auth',
                name:'auth',
                component:Auth,
                redirect:{name: 'login'},
                meta:{
                    isGuest:true,
                    sidebar:false,
                    footer:false
                },
                children:[
                    {
                        path:'login',
                        name:'login',
                        component:Login,
                        meta:{
                            header:false,
                            footer:false,
                            sidebar:false
                        }
                    },
                    {
                        path:'register',
                        name:'register',
                        component:Register,
                        meta:{
                            header:false,
                            footer:false,
                            sidebar:false
                        }
                    },
                    {
                        path:'forgotPassword',
                        name:'forgotPassword',
                        component:ForgotPassword,
                        meta:{
                            header:false,
                            footer:false,
                            sidebar:false
                        }
                    },
                    {
                        path:'updatePassword/:token',
                        name:'updatePassword',
                        component:UpdatePassword,
                        meta:{
                            header:false,
                            footer:false,
                            sidebar:false
                        }
                    }
                ]
            }
        ]
    },
    // dashboard path
    {
        path:'/DashboardLayout',
        name:'dashboardLayout',
        redirect:'dashboard',
        component:DashboardLayout,
        meta:{isAuthenticate:true},
        children:[
            {
                path:'/Dashboard',
                name:'dashboard',
                component:Dashboard
            },
            {
                path:'/Dashboard/Products',
                name:'dProducts',
                component:DProducts
            },
            {
                path:'/Dashboard/Categories',
                name:'dCategories',
                component:DCategories
            },
            {
                path:'/Dashboard/Profile',
                name:'dProfile',
                component:DProfile
            },
            {
                path:'/Dashboard/Users',
                name:'dUsers',
                component:DUsers,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Orders',
                name:'dOrders',
                component:DOrders,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Sliders',
                name:'dSliders',
                component:DSliders,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Images',
                name:'dImages',
                component:DImages,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Icons',
                name:'dIcons',
                component:DIcons,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Languages',
                name:'dLangs',
                component:DLangs,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Translations',
                name:'dTranslations',
                component:DTranslations,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Settings',
                name:'dSettings',
                component:DSettings,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/Notifications',
                name:'dNotifications',
                component:DNotifications,
                meta:{isAdmin:true}
            },
            {
                path:'/Dashboard/OrderDetails/:orderId',
                name:'dOrderDetails',
                component:DOrderDetails,
                meta:{isAdmin:true}
            }
        ]
    },
    
]


const router = new VueRouter({
    mode:'history',
    routes
})


router.beforeEach((to,from,next) => {
    Nprogress.start()
    next()
    store.dispatch('alert/removeAlert', {root:true})
    const user = JSON.parse(localStorage.getItem('user'))
    if(to.matched.some(record => record.meta.isLoggedIn)){
        if(!user){
            next({name:'cart'})
        }else{
            next()
        }  
    }

    if(to.matched.some(record => record.meta.isAuthenticate)){
        if(!user){
            next({name:'login'})
        }else{
            if(user.role == 'publisher' || user.role == 'admin'){
                next()
            }else{
                next({name:'cart'})
            }
        }  
    }

    if(to.matched.some(record => record.meta.isAdmin)){
        if(!user){
            next({name:'login'})
        }else{
            if(user.role == 'admin'){
                next()
            }else{
                next({name:'dashboard'})
            }
        }  
    }
    
    if(to.matched.some(record => record.meta.isGuest)){
        if(user){
            next({name:'dashboard'})
        }else{
            next()
        }  
    }
})

router.beforeResolve((to,from,next) => {
    Nprogress.done()
    next()
})

export default router