import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        cats:[],
        cat:{
            name:''
        },
        defaultCat:{
            name:''
        },
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,

    },
    getters:{
        getCat: state => id => {
            return state.cats.filter(cat => cat._id == id)
        }
    },
    mutations:{
        SET_CATS: (state, payload) => {
            state.cats = payload
        },
        SET_CAT: (state, payload) => {
            state.cat = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_CAT: (state) => {
            state.cat = Object.assign({}, state.defaultCat)
        },
        SET_EDIT_CAT: (state,payload) => {
            state.cat = Object.assign({}, payload)
        }
    },
    actions:{
        // fetch all categoreis
        fetchCats: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/categories')
                commit('SET_CATS', data.data.cats)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add categories
        addCat: async ({state ,dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/categories', state.cat)
                dispatch('alert/setAlert', {
                    text:'Category added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_CAT')
                dispatch('fetchCats')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete cat
        deleteCat: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/categories/'+id,)
                dispatch('alert/setAlert', {
                    text:'Category deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchCats')
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update cat
        updateCat: async ({state , dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/categories/'+state.cat._id, state.cat)
                dispatch('alert/setAlert', {
                    text:'Category updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_CAT')
                dispatch('fetchCats')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit cat
        setEditCat: ({commit}, payload) => {
            commit('SET_EDIT_CAT', payload)
        },
        // set default cat
        setDefaultCat: ({commit}) => {
            commit('SET_DEFAULT_CAT')
        }
    }
}