import setErr from '../../utils/ResponseError'
import Axios from 'axios'

export default {
    namespaced:true,
    state:{
        notifications:[],
        notification:{},
        loading:false,
        loadingBtn:false,
        edit:false,
    },
    getters:{
        notificationLength: (state) => {
            let no = state.notifications.filter(item => !item.read)
            return Number(no.length)
        }
    },
    mutations:{
        SET_NOTIFICATIONS: (state, payload) => {
            state.notifications = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        }
    },
    actions:{
        // fetch all notifications
        fetchNotifications: async ({commit,rootState}) => {
            try {
                commit('SET_LOADING', true)
                let userId = rootState.auth.user._id
                const data = await Axios.get('/api/notifications/'+userId)
                commit('SET_NOTIFICATIONS', data.data.notifications)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
            }
        },
        // read NOTIFICATION
        readNotification: async ({dispatch , commit},id) => {
            try {
                commit('SET_BTN_LOADING', true)
                commit('SET_LOADING', true)
                const data = await Axios.put('/api/notifications/'+id)
                console.log(data)
                commit('SET_BTN_LOADING', false)
                dispatch('fetchNotifications')
            } catch (error) {
                commit('SET_LOADING', false)
                commit('SET_BTN_LOADING', false)
                console.log(error.response)
            }
        },
        // read all NOTIFICATIONS
        readAllNotifications: async ({dispatch , commit, rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                const userId = rootState.auth.user._id
                await Axios.put('/api/notifications/all/'+userId)
                commit('SET_BTN_LOADING', false)
                dispatch('fetchNotifications')
            } catch (error) {
                commit('SET_LOADING', false)
                commit('SET_BTN_LOADING', false)
                console.log(error.response)
            }
        },
    }
}