import setErr from '../../utils/ResponseError'
import formData from '../../utils/DataForm'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        path:process.env.NODE_ENV == 'development' ? 'http://localhost:5000/uploads/users/' : location.origin+'/uploads/users/',
        users:[],
        user:{
            name:'',
            email:'',
            role:'',
            password:'',
            avatar:'',
            bio:''
        },
        defaultUser:{
            name:'',
            email:'',
            role:'',
            password:'',
            avatar:'',
            bio:'',
            address:{
                address1:'',
                address2:'',
                country:'',
                city:'',
                state:'',
                phone:'',
                zip:''
            }
        },
        avatarUrl:null,
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,
    },
    getters:{
       getUser(){}
    },
    mutations:{
        SET_USERS: (state, payload) => {
            state.users = payload
        },
        SET_USER: (state, payload) => {
            state.user = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_USER: (state) => {
            state.user = Object.assign({}, state.defaultUser)
        },
        SET_EDIT_USER: (state,payload) => {
            state.user = Object.assign({}, payload)
        },
        SET_AVATAR_URL: (state, payload) => {
            state.avatarUrl = payload
        },
        SET_AVATAR: (state, payload) =>{
            state.user.avatar = payload
        } 
    },
    actions:{
        // fetch all users
        fetchUsers: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/users')
                commit('SET_USERS', data.data.users)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        fetchUser: async ({commit}, id) => {
            try {
                const user = await Axios.get('/api/users/'+id)
                commit('SET_USER', user)
                return user
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add new user
        addUser: async ({state ,dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/users',state.user)
                dispatch('alert/setAlert', {
                    text:'User added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_USER')
                dispatch('fetchUsers')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // add new user
        updateUser: async ({state , dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/users/'+state.user._id,state.user)
                dispatch('alert/setAlert', {
                    text:'User updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_USER')
                dispatch('fetchUsers')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete user
        deleteUser: async ({dispatch, commit ,rootState},id) => {
            try {
                
                if(rootState.auth.user.id == id){
                    if(confirm('Are You sure You want to delete your own account?')){
                        await apiClient.deleteUser(id)
                        dispatch('auth/logout', null , {root:true})
                    }
                }else{
                    await Axios.delete('/api/users/'+id)
                        dispatch('alert/setAlert', {
                            text:'User deleted Successfully',
                            type:'success',
                            display:'dataTable'
                        } , {root:true})
                        dispatch('fetchUsers')
                }
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit cat
        setEditUser: ({commit,state}, payload) => {
            commit('SET_EDIT_USER', payload)
            let avatarUrl = payload.avatar ? state.path+payload.avatar : null
            // set avatar url
            commit('SET_AVATAR_URL', avatarUrl)
            // set avatar to null
            commit('SET_AVATAR', null)
        },
        // set default cat
        setDefaultUser: ({commit}) => {
            commit('SET_DEFAULT_USER')
        },
        // upload Image
        uploadImage: ({state, commit}) => {
            let image = state.user.avatar
            if(image){
                if(image.type.startsWith('image') && image.size <= 2048000){
                    const fileReader = new FileReader()
                    fileReader.addEventListener('load', () => {
                        const result = fileReader.result
                        commit('SET_AVATAR_URL', result)
                    })
                    fileReader.readAsDataURL(image)
                }
            }else{
                commit('SET_AVATAR_URL', state.path+state.user.avatar)
            }
            
        },
        // update Profile
        updateProfile: async ({state , dispatch , commit,rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                // some settings to update the profile
                let user = state.user
                if(!user.avatar){
                    delete user.avatar
                }
                delete user.token
                const id = user._id
                let address = state.user.address
                if(address){
                    address = formData(state.user.address)
                }
                delete state.user.address
                const payload = formData(state.user)
                if(address){
                    for (var pair of address.entries()) {
                        payload.append(pair[0], pair[1]);
                    }
                }
                await Axios.put('/api/users/profile/'+id,payload)
                const data = await dispatch('fetchUser', id)
                const newUser = data.data.data
                newUser.token = rootState.auth.user.token
                dispatch('auth/setUser', newUser, { root:true })
                dispatch('snackbar/setSnackbar', {
                    text:'Profile updated Successfully',
                    type:'success',
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                location.reload()
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
    },
}