<template>
  <v-menu offset-y>
      
    <template v-slot:activator="{ on }">
        <div class="dashboard-menu" v-on="on">
            <small v-on="on" class="mr-2">{{ auth.user.name }}</small>
            <v-avatar left size="35" color="dark"  class="hover">
            <!-- <v-icon small dark>mdi-chevron-down</v-icon> -->
                <img size="20" :src="setting.settings.images.url+'/users/'+auth.user.avatar">
            </v-avatar>
       </div>
    </template>
    <v-list dense>
        <v-list-item
        v-for="(link, index) in links"
        :key="index"
        link
        exact
        :to="link.route"
        class="mx-0"
        >
                <!-- <v-list-item-action> -->
                <v-icon small class="pr-3">{{ link.icon }}</v-icon>
                <!-- </v-list-item-action> -->
                <v-list-item-content>
                <v-list-item-title small link>{{ $t(`dashboard_navbar.${link.name}`) }}</v-list-item-title>
                </v-list-item-content>
        </v-list-item>
        <v-divider></v-divider>
        <v-list-item @click="logout">
            <v-list-item-action class="mr-3">
                <v-icon>mdi-logout</v-icon>
            </v-list-item-action>
            <v-list-item-content>
                <v-list-item-title link>{{ $t('dashboard_navbar.logout') }}</v-list-item-title>
            </v-list-item-content>
        </v-list-item>
      
    </v-list>
</v-menu>
</template>

<script>
import { mapActions, mapState } from 'vuex'
export default {
    data(){
        return {
            links:[
                { icon: 'mdi-home', name:'home', route:{name:'products'} },
                { icon: 'mdi-cog-outline', name:'dashboard', route:{name:'dashboard'} },
                { icon: 'mdi-account-cowboy-hat', name:'profile', route:{name:'dProfile'} },
            ],
        }
    },
    methods: {
      ...mapActions('auth', ['logout'])
    },
    computed:{
        ...mapState(['auth', 'setting'])
    }
}
</script>

<style>
    .dashboard-menu{
        cursor: pointer;
    }
</style>