import setErr from '../../utils/ResponseError'
import formData from '../../utils/DataForm'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        path:process.env.NODE_ENV == 'development' ? 'http://localhost:5000/uploads/images' : location.origin+'/uploads/images',
        images:[],
        image:{
            type:'',
            image:null,
        },
        defaultImage:{
            type:'',
            image:null,
        },
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,
        imageUrl:null
    },
    getters:{
        getImage: state => type => {
            let images = state.images.filter(img => img.type == type)
            let img = images[0]
            if(img){
                return state.path+img.image
            }else{
                return 'https://picsum.photos/750/565?random'
            }
        }
    },
    mutations:{
        SET_IMAGES: (state, payload) => {
            state.images = payload
        },
        SET_IMAGE: (state, payload) => {
            state.image = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_IMAGE: (state) => {
            state.image = Object.assign({}, state.defaultImage)
        },
        SET_EDIT_IMAGE: (state,payload) => {
            state.image = Object.assign({}, payload)
        },
        SET_IMAGE_URL: (state, payload) => {
            state.imageUrl = payload
        },
        SET_IMAGE: (state, payload) =>{
            state.image.image = payload
        } 
    },
    actions:{
        // fetch all images
        fetchImages: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/images')
                commit('SET_IMAGES', data.data.images)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add image
        addImage: async ({dispatch , commit, state}) => {
            try {
                commit('SET_BTN_LOADING', true)
                const payload = formData(state.image);
                await Axios.post('/api/images',payload)
                dispatch('alert/setAlert', {
                    text:'Image added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_IMAGE')
                dispatch('fetchImages')
            } catch (error) {
                console.log(error.response)
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete image
        deleteImage: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/images/'+id)
                dispatch('alert/setAlert', {
                    text:'Image deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchImages')
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update image
        updateImage: async ({state , dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = state.image
                if(!data.image){
                    delete data.image
                }
                const image = formData(data)
                await Axios.put('/api/images/'+state.image._id,image)
                dispatch('alert/setAlert', {
                    text:'Image updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_IMAGE')
                dispatch('fetchImages')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit image
        setEditImage: ({commit,state}, payload) => {
            commit('SET_EDIT_IMAGE', payload)
            let imageUrl = payload.image ? `${state.path}/${payload.image}` : null
            // set image url
            commit('SET_IMAGE_URL', imageUrl)
            // set image to null
            commit('SET_IMAGE', null)
        },
        // set default IMAGE
        setDefaultImage: ({commit}) => {
            commit('SET_DEFAULT_IMAGE')
            commit('SET_IMAGE_URL', null)
        },
        // upload Image
        uploadImage: ({state, commit}) => {
            let image = state.image.image
            if(image){
                if(image.type.startsWith('image') && image.size <= 2048000){
                    const fileReader = new FileReader()
                    fileReader.addEventListener('load', () => {
                        const result = fileReader.result
                        commit('SET_IMAGE_URL', result)
                    })
                    fileReader.readAsDataURL(image)
                }
            }else{
                commit('SET_IMAGE_URL', null)
            }
            
        }
    }
}