<template>
  <div>
    <v-navigation-drawer
      v-model="drawer"
      app
      color="primary"
      dark
    >
    
    <v-list dense>
      <v-list-item two-line>
          <v-list-item-avatar>
            <img :src="setting.settings.images.imageUrl+'/users/'+auth.user.avatar">
          </v-list-item-avatar>

          <v-list-item-content>
            <v-list-item-title>{{ auth.user.name }}</v-list-item-title>
            <v-list-item-subtitle>{{ $t(`dashboard_navbar.loggedin`) }}</v-list-item-subtitle>
          </v-list-item-content>
        </v-list-item>
        <v-divider></v-divider>
      <div
        v-for="item in items"
        :key="item.text"
      >
      <v-list-item v-if="!item.children && isAuthorized(item.role)"
        link
        exact
        :to="item.route"
        color="dark"
      >
        <v-list-item-action>
                <v-icon>{{ item.icon }}</v-icon>
          </v-list-item-action>
          <v-list-item-content>
            <v-list-item-title>{{ $t(`dashboard_navbar.${item.text}`) }}</v-list-item-title>
          </v-list-item-content>
      </v-list-item>
      <div v-else>
      <v-list-group
        v-if="isAuthorized(item.role)"
        v-model="item.active"
        :prepend-icon="item.icon"
        no-action
        color="dark"
        class="my-1"
      >
        <template v-slot:activator>
          <v-list-item-content>
            <v-list-item-title>{{ $t(`dashboard_navbar.${item.text}`) }}</v-list-item-title>
          </v-list-item-content>
        </template>

        <div class="white ml-4 mr-2 my-2 sublist">
        <template v-if="item.children">
          <div 
            v-for="subItem in item.children"
            :key="subItem.text"
          >
        <v-list-item
          class="subitem"
          v-if="isAuthorized(subItem.role)"
          link
          exact
          :to="subItem.route"
          :prepend-icon="subItem.icon"
        >
          <v-list-item-action >
                <v-icon class="black--text">{{ subItem.icon }}</v-icon>
          </v-list-item-action>
          <v-list-item-content class="black--text">
            <v-list-item-title>{{ $t(`dashboard_navbar.${subItem.text}`) }}</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
        </div>
        </template>
        </div>
      </v-list-group>
      </div>
      <v-divider></v-divider>
      </div>
    </v-list>
    </v-navigation-drawer>

    <v-app-bar
      app
      color="light"
    >
      <v-app-bar-nav-icon @click.stop="drawer = !drawer" />
      <v-toolbar-title
        class="ml-0 pl-4"
      >
        <span class="hidden-sm-and-down">{{ $t('dashboard_navbar.brand') }}</span>
      </v-toolbar-title>
      <v-spacer></v-spacer>
      <v-text-field
        flat
        solo-inverted
        hide-details
        prepend-inner-icon="mdi-magnify"
        :label="$t('dashboard_navbar.search')"
        class="hidden-sm-and-down"
      />
      <v-spacer />

      <Notifications v-if="isAuthorized('admin')"/>

      <LanguageSwitcher />
      <v-divider vertical class="mx-4"></v-divider>
      <!-- Dashboard menu -->
      <Menu />
      
    </v-app-bar>
    
  </div>
</template>

<script>
  import Menu from '@/components/navigation/Menu'
  import Notifications from '@/components/navigation/Notifications'
  import LanguageSwitcher from '@/components/navigation/LanguageSwitcher'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    props: {
      source: String,
    },
    data: () => ({
      dialog: false,
      drawer: null,
      items: [
        { icon: 'mdi-home', text: 'home', route:{name:'products'} },
        { icon: 'mdi-cog-outline', text: 'dashboard', route:{name:'dashboard'} },
        {
          icon: 'mdi-shopping',
          text: 'products',
          active: false,
          children: [
            { icon: 'mdi-shape', text: 'categories', route:{name:'dCategories'} },
            { icon: 'mdi-shopping', text: 'products', route:{name:'dProducts'} },
            { icon: 'mdi-cart-outline', text: 'orders', route:{name:'dOrders'}, role:'admin' },
          ],
        },
        { icon: 'mdi-cog-outline', text: 'settings', route:{name:'dSettings'} },
        { icon: 'mdi-account-group', text: 'users', route:{name:'dUsers'} },
        { icon: 'mdi-account-cowboy-hat', text: 'profile', route:{name:'dProfile'} },
        { icon: 'mdi-bell', text: 'notifications', route:{name:'dNotifications'} },
        { 
          icon: 'mdi-apps', 
          text: 'utilities',
          role:'admin',
          active:false,
          children:[
            { icon: 'mdi-image-move', text: 'slider', route:{name:'dSliders'} },
            { icon: 'mdi-tooltip-image', text: 'images', route:{name:'dImages'} },
            { icon: 'mdi-emoticon-outline', text: 'icons', route:{name:'dIcons'} },
          ]  
        },
        { 
          icon: 'mdi-flag', 
          text: 'localization',
          role:'admin',
          active:false,
          children:[
            { icon: 'mdi-image-move', text: 'languages', route:{name:'dLangs'} },
            { icon: 'mdi-tooltip-image', text: 'translations', route:{name:'dTranslations'} },
          ]  
        },
      ],
    }),
    computed:{
      ...mapState(['auth', 'setting']),
      ...mapGetters('auth', ['isAuthorized'])
    },
    components:{
      Menu,
      LanguageSwitcher,
      Notifications
    }
  }
</script>

<style lang="css">
  .sublist{
    border-radius: 10px;
  }
  .subitem:first-child {
    border-top-left-radius: 10px;
    border-top-right-radius: 10px;
  }
  .subitem:last-child {
    border-bottom-left-radius: 10px;
    border-bottom-right-radius: 10px;
  }
</style>