<template>
  <v-content>
      <v-container>
          <v-row>
              <v-col>
                    <!-- <Checkout /> -->
              </v-col>
          </v-row>
          <v-row>
            <v-col cols="12" lg="8" class="mx-auto">
                <v-card>
                    <v-toolbar color="dark" dark>
                        <v-toolbar-title class="mx-auto">
                            <h1>{{ $t('cart_page.heading') }}</h1>
                        </v-toolbar-title>
                    </v-toolbar>

                    <!-- Cart items component -->
                    <v-card-text v-if="hasProduct">
                        <CartItems />
                    </v-card-text>
                    <v-card-text v-else class="py-5 text-center">
                        <h2>{{ $t('cart_page.empty_cart') }}</h2>
                    </v-card-text>

                    <v-card-actions v-if="hasProduct">
                        <h2>{{ $t('cart_page.total') }}: </h2>
                        <v-spacer></v-spacer>
                        <h2>${{ totalPrice }}</h2>
                    </v-card-actions>
                    <v-card-actions v-if="hasProduct">
                        <v-btn color="dark" dark @click="goToCheckout">
                            {{ $t('cart_page.go_to_checkout') }}
                        </v-btn>
                    </v-card-actions>
                </v-card>
            </v-col>
          </v-row>
          <v-row justify="center">
            <v-dialog
            v-model="dialog"
            max-width="290"
            >
            <v-card>
                <v-card-title class="headline">{{ $t('cart_page.modal_heading') }}</v-card-title>

                <v-card-text>
                    {{ $t('cart_page.modal_text') }}
                </v-card-text>

                <v-card-actions>
                <v-spacer></v-spacer>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'register'}"
                >
                    {{ $t('cart_page.modal_register') }}
                </v-btn>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'login'}"
                >
                    {{ $t('cart_page.modal_login') }}
                </v-btn>
                </v-card-actions>
            </v-card>
            </v-dialog>
        </v-row>
      </v-container>
  </v-content>
</template>

<script>
import CartItems from '@/components/cart/CartItems'
import { mapActions , mapState , mapGetters } from 'vuex'
export default {
    data() {
        return {
            paymentMethod:false,
            dialog:false
        }
    },
    computed: {
        ...mapState(['cart']),
        ...mapGetters('cart', ['hasProduct', 'cartLength', 'totalPrice']),
        ...mapGetters('auth', ['isLoggedIn'])
    },
    methods:{
        ...mapActions('cart', ['setCart']),
        goToCheckout(){
            if(this.isLoggedIn){
                this.$router.push({name:'checkout'})
            }else{
                this.dialog = true
            }
        }
    },
    created(){
        this.setCart()
    },
    components:{
        CartItems,
        // StripeCheckout,
        // PaypalCheckout,
        // Checkout,
    }
}
</script>

