<template>
  <v-menu offset-y class="my-0 py-0">
      
    <template v-slot:activator="{ on }">
        <div class="notification-menu" v-on="on">
            <v-badge
                left
                overlap
                :content="notificationLength"
            >
                <v-icon>
                    mdi-bell
                </v-icon>
            </v-badge>
       </div>
    </template>
    <v-list class="my-0 py-0">
        <v-list-item class="py-0 primary justify-center" dark>
                <small
                    @click="readAllNotifications" 
                    class="mark-all-link"
                >{{ $t('notifications.mark_all_as_read') }}</small>
        </v-list-item>
        <v-list-item v-if="notification.notifications.length < 1" class="py-0 justify-center">
                <small>{{ $t('notifications.no_notifications') }}</small>
        </v-list-item>
        <div
             v-for="(link, i) in notification.notifications"
            :key="i"
        >
        <v-list-item
            v-if="i < 5"
            :class="!link.read ? 'light': 'light lighten-1'"
            light
            class="mx-0"
            link
            exact
            small
            @click="itemClicked(link._id,link.data)"
        >
                <v-list-item-icon class="mr-2">
                    <v-icon>mdi-cart</v-icon>
                </v-list-item-icon>
                <v-list-item-content>
                <v-list-item-title link>
                    <small>{{ $t('notifications.order') }}</small>
                </v-list-item-title>
                </v-list-item-content>
        </v-list-item>
      </div>
      <v-list-item 
        link
        :to="{name:'dNotifications'}"
        class="py-0 primary justify-center" dark
        
        >
                <small 
                    class="show-all-link"
                >
                {{ $t('notifications.show_all') }}
                </small>
        </v-list-item>
    </v-list>
</v-menu>
</template>

<script>
import { mapActions, mapState, mapGetters } from 'vuex'
export default {
    data(){
        return {
            links:[
                { icon: 'mdi-home', name:'home', route:{name:'products'} },
                { icon: 'mdi-cog-outline', name:'dashboard', route:{name:'dashboard'} },
                { icon: 'mdi-account-cowboy-hat', name:'profile', route:{name:'dProfile'} },
            ],
        }
    },
    methods: {
      ...mapActions('notification', ['fetchNotifications', 'readAllNotifications', 'readNotification']),
      itemClicked(id,data){
          this.readNotification(id,data)
          this.$router.push({name:'dOrderDetails', params:{orderId:data}})
      }
    },
    created(){
        this.fetchNotifications()
        let self = this
        setInterval(function(){
            self.fetchNotifications()
        }, 20000)
    },
    computed:{
        ...mapState(['auth', 'notification']),
        ...mapGetters('notification', ['notificationLength'])
    },
}
</script>

<style>
    .notification-menu{
        cursor: pointer;
    }
    .mark-all-link{
        font-size: .7rem;
        cursor: pointer;
    }
    .mark-all-link:hover{
        text-decoration: underline;
    }
</style>