import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        settings:{
            images:{
                url:process.env.NODE_ENV == 'development' ? 'http://localhost:5000/uploads' : location.origin+'/uploads'
            },
            site:{
                url:process.env.NODE_ENV == 'development' ? 'http://localhost:5000' : location.origin,
                api:process.env.NODE_ENV == 'development' ? 'http://localhost:5000/api' : location.origin+'/uploads'
            },
            payment:{
                stripe:false,
                paypal:true
            }
        },
        loading:false,
        loadingBtn:false,
    },
    getters:{
        
    },
    mutations:{
        SET_SETTINGS: (state, payload) => {
            state.settings.payment = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        }
    },
    actions:{
        // set Default Settings
        fetchSettings: async ({dispath, commit, state, rootState}) => {
            try {
                commit('SET_LOADING', true)
                let data = await Axios.get('/api/settings')
                commit('SET_SETTINGS', data.data.settings.payment)
                commit('SET_LOADING', false)
            } catch (error) {
                console.log(error)
                commit('SET_LOADING', false)
            }
        },
        // update settings
        updateSettings: async ({dispatch, commit, state}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/settings', state.settings)
                dispatch('alert/setAlert', {
                    text:'Settings updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                dispatch('fetchSettings')
            } catch (error) {
                console.log(error.response)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
            }
        },
        // get payment gateway keys
        getKey: async ({}, type) => {
            try {
                const data = await Axios.post('/api/payments/getKey',type)
                return data.data.key
            } catch (error) {
                return false
            }
        }
    }
}