<template>
      <v-col>
          <v-card>
              <v-toolbar dark color="primary">
                  <v-toolbar-title>
                      {{ $t('dashboard_page.top_selling_products') }}
                  </v-toolbar-title>
              </v-toolbar>
              <v-list>
                <v-list-group
                    v-for="(product, i) in product.topSellingProducts"
                    :key="i"
                >
                    <template v-slot:activator>
                    <v-list-item-icon>
                    #{{ i+1 }}
                    </v-list-item-icon>
                    <v-list-item-content>
                        
                        <v-list-item-title v-text="product.name"></v-list-item-title>
                    </v-list-item-content>
                    </template>

                    <v-list-item>
                    <v-list-item-content>
                        <v-container>
                            <v-row>
                                <v-col cols="12" md="4" sm="6" class="mx-auto">
                                    <v-card
                                    >
                                        <v-img
                                        v-if="product.avatar"
                                        height="250"
                                        :src="setting.settings.images.url+'/products/'+product.avatar"
                                        ></v-img>

                                        <v-card-title>
                                            <router-link :to="{name:'singleProduct', params:{productId:product._id}}">
                                                {{ product.name }}
                                            </router-link>
                                        </v-card-title>

                                        <v-card-text>
                                        <v-row
                                            align="center"
                                            class="mx-0"
                                        >
                                            <v-rating
                                                :value="productRating(product.reviews)"
                                                color="amber"
                                                dense
                                                half-increments
                                                readonly
                                                size="14"
                                            ></v-rating>

                                            <div class="grey--text ml-4">{{ productRating(product.reviews) }} ({{ productReviewsCount(product.reviews) }})</div>
                                        </v-row>

                                        <div class="my-4 subtitle-1">
                                            <h3 right class="mr-3 primary--text">${{ product.price }}</h3>
                                        </div>
                                        <div class="my-4 subtitle-1">
                                            <h3 right class="mr-3 primary--text">Total Sales: {{ product.sales }}</h3>
                                        </div>

                                        <div>
                                            {{ product.excerpt }}
                                        </div>
                                        </v-card-text>

                                    </v-card>
                                </v-col>
                            </v-row>
                        </v-container>
                    </v-list-item-content>
                    </v-list-item>
                </v-list-group>
                </v-list>
          </v-card>
      </v-col>
</template>

<script>
import { mapState, mapGetters } from 'vuex'
export default {
    data(){
        return {
        }
    },
    computed:{
        ...mapState(['product', 'setting']),
        ...mapGetters('product', ['productRating','productReviewsCount']),
    }
}
</script>

