<template>
    <v-col class="mb-3" cols="12" sm="6" md="3">
        <v-card :style="cardStyle" class="cardClass">
            <v-row class="card-row" align="center">
                <v-col cols="9">
                    <v-card-text>
                        <h4 :style="headingStyle">{{ heading }}</h4>
                        <h2 class="numberClass my-3">{{ number }}</h2>
                    </v-card-text>
                </v-col>
                <v-col cols="3" class="col-auto">
                    <v-card-text>
                        <v-icon color="grey lighten-1" style="font-size:2rem">{{ icon }}</v-icon>
                    </v-card-text>
                </v-col>
            </v-row>
        </v-card>
    </v-col>
</template>

<script>
export default {
    props:['color','icon','heading','number'],
    computed:{
        cardStyle(){
            return {
                'border-left':`5px solid ${this.color} !important`
            }
        },
        headingStyle(){
            return {
                'color':`${this.color}`
            }
        }
    }
}
</script>

<style>
    .numberClass{
        font-weight: 400;
    }
    .cardClass{
        min-height: 110px;
        position: relative;
    }
    .card-row{
        position: absolute;
        height: 100%;
        width: 100%;
        top: 0;
        left: 0;
    }
</style>