<template>
  <v-container>
    <!-- <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn> -->
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="order.orders"
          :search="search"
          :loading="order.loading"
          item-key="_id"
          :single-select="singleSelect"
          sort-by="-date"
          class="elevation-1"
        >
        <!-- Date Template -->
        <template v-slot:item.date="{ item }">
            <span>{{item.date | formatDate}}</span>
        </template>
        <template v-slot:item.amount="{ item }">
            <span>$ {{item.amount}}</span>
        </template>
          <template v-slot:top>
            <v-toolbar color="light darken-1">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.orders') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog v-model="order.dialog" max-width="500px">
                <v-card>
                  <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
                    <v-card-title>
                      <span class="headline">
                        {{
                           !order.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.order') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.order') 
                        }}
                      </span>
                    </v-card-title>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                             <v-select
                              :items="status"
                              :label="$t('dashboard_input_labels.status')"
                              prepend-icon="mdi-shape"
                              dense
                              v-model="order.order.status"
                            ></v-select>
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="order.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="primary"
              class="mr-2"
              @click="goToOrderDetails(item._id)"
            >
              mdi-eye
            </v-icon>
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
  import moment from 'moment'
  import OrderProducts from '@/components/dashboard/order/OrderProducts'
  import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      status:['recieved', 'processing', 'delivered'],
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      headers: [
        {
          text: vm.$t('dashboard_datatable.date'),
          align: 'start',
          value: 'date',
        },
        { text: vm.$t('dashboard_datatable.status'), value: 'status' },
        { text: vm.$t('dashboard_datatable.amount'), value: 'amount' },
        { text: vm.$t('dashboard_datatable.payment'), value: 'payment' },
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ],
    }),
    mixins:[formValidations],
    computed: {
      ...mapState(['order' , 'alert']),
      ...mapGetters('order',['getOrder'])
    },
    components:{
      OrderProducts
    },

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('order', ['fetchOrders', 'addOrder', 'setDialog', 'deleteOrder', 'updateOrder', 'setEditOrder', 'setDefaultOrder']),
      // initialize the data table
      async initialize () {
        await this.fetchOrders()
      },
      // edit item
      async editItem (item) {
        this.setEditOrder(item)
        this.setDialog({dialog:true,edit:true})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // go to order details
      async goToOrderDetails (id) {
        this.$router.push({name:'dOrderDetails', params:{orderId:id}})
      },
      // delete item
      async deleteItem (item) {
        if(confirm('Are you sure you want to delete this Order?')){
          await this.deleteOrder(item._id)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.setDefaultOrder()
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.setDialog({dialog:false,edit:false})
        this.setDefaultOrder()
        this.$refs.modalForm.resetValidation()
      },
      // submit the form
      async save () {
        if (this.order.edit) {
          await this.updateOrder()
        } else {  
          await this.addOrder()
        }
        this.$refs.modalForm.resetValidation()
      },
    },
    filters:{
        formatDate(value) {
            if (value) {
                return moment(String(value)).format('MM/DD/YYYY hh:mm')
            }
        }
    }
  }
</script>