import setErr from '../../utils/ResponseError'
import formData from '../../utils/DataForm'
import Axios from 'axios'

export default {
    namespaced:true,
    state:{
        count:0,
        total:0,
        limit:5,
        products:[],
        topSellingProducts:[],
        product:{
            name:'',
            category:'',
            excerpt:'',
            link:'',
            type:'physical',
            description:'',
            price:'',
            avatar:null,
            images:[],
        },
        defaultProduct:{
            name:'',
            category:'',
            excerpt:'',
            type:'physical',
            link:'',
            description:'',
            price:'',
            avatar:null,
            images:[],
        },
        avatarUrl:null,
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,

    },
    getters:{
        getProduct: state => id => {
            return state.products.filter(product => product._id == id)
        },
        getLoadingBtn: state => {
            return state.loadingBtn
        },
        productReviewsCount: state => reviews => {
            return reviews ? reviews.length : 0
        },
        productRating: state => reviews => {
            let totalReviews = reviews ? reviews.length : 0
            let totalRatings = 0
            if(totalReviews > 0){
                totalRatings = reviews.reduce((current, next) => 
                current + next.rating, 0)
            }
            let result = totalReviews > 0 ? totalRatings/totalReviews : 0
            return Number(result.toFixed(1))
        },
        getPaginationLength: state => {
            let length = state.total / state.limit
            return Number(Math.ceil(length))
        },
        topSellingProducts: (state) => (length) => {
            let products = []
            for( let i of state.products){
                products.push(i)
                if(state.products.length == length){
                    break
                }
                return products
            }
        }
    },
    mutations:{
        SET_TOP_SELLING_PRODUCTS: (state, payload) => {
            state.topSellingProducts = payload
        },
        SET_PRODUCTS: (state, payload) => {
            state.products = payload
        },
        SET_PRODUCT: (state, payload) => {
            state.product = payload
        },
        SET_COUNT: (state, payload) => {
            state.count = payload
        },
        SET_TOTAL: (state, payload) => {
            state.total = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_PRODUCT: (state) => {
            state.product = Object.assign({}, state.defaultProduct)
        },
        SET_EDIT_PRODUCT: (state,payload) => {
            state.product = Object.assign({}, payload)
        },
        SET_AVATAR_URL: (state, payload) => {
            state.avatarUrl = payload
        },
        SET_AVATAR: (state, payload) =>{
            state.product.avatar = payload
        } 
    },
    actions:{
        // fetch all products
        fetchProducts: async ({dispatch,commit}, payload) => {
            try {
                if(!payload){
                    payload = {}
                }
                commit('SET_LOADING', true)
                dispatch('cat/fetchCats', null , {root:true})
                const data = await Axios.get('/api/products', {
                    params:{
                        payload
                    }
                })
                commit('SET_PRODUCTS', data.data.products)
                commit('SET_COUNT', data.data.count)
                commit('SET_TOTAL', data.data.total)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // fetch single product
        fetchProduct: async ({commit, getters}, payload) => {
            try {
                commit('SET_LOADING', true)
                let result = getters.getProduct(payload)
                let product = result[0]
                if(product){
                    commit('SET_PRODUCT', product)
                }else{
                    let result = await Axios.get('/api/products/'+payload)
                    product = result.data.product
                    commit('SET_PRODUCT', product)
                }
                commit('SET_LOADING', false)
                return product
            } catch (error) {
                commit('SET_LOADING', false)
                return false
            }
        },
        // add products
        addProduct: async ({state ,dispatch , commit, rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = state.product
                data.user = rootState.auth.user._id
                const payload = formData(data);
                await Axios.post('/api/products' , payload)
                dispatch('alert/setAlert', {
                    text:'Product added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_PRODUCT')
                let newData = {limit:1000}
                let user = rootState.auth.user
                if(user.role == 'publisher'){
                    newData.user = user._id
                }
                dispatch('fetchProducts', newData)
            } catch (error) {
                console.log(error.response)
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // add review
        addReview: async ({state ,dispatch , commit, rootState}, payload) => {
            try {
                let reviewUsers = state.product.reviews.map(function(arr){
                    return arr.user._id
                })
                commit('SET_BTN_LOADING', true)
                if(!rootState.auth.user){
                    dispatch('snackbar/setSnackbar', {
                        text:'You have to login first to add a review',
                        type:'error'
                    }, {root:true})
                    commit('SET_BTN_LOADING', false)
                    return false
                  }
                  if(state.product.user._id == rootState.auth.user._id){
                    dispatch('snackbar/setSnackbar', {
                        text:'You can not give review to your own product',
                        type:'error'
                    }, {root:true})
                    commit('SET_BTN_LOADING', false)
                    return false
                }
                if(reviewUsers.includes(rootState.auth.user._id)){
                    dispatch('snackbar/setSnackbar', {
                        text:'You have already given the review',
                        type:'error'
                    }, {root:true})
                    commit('SET_BTN_LOADING', false)
                    return false
                }
                await Axios.put(`/api/products/${payload.productId}/${payload.userId}`, payload.review)
                let data = await Axios.get('/api/products/'+payload.productId)
                let product = data.data.product
                commit('SET_PRODUCT', product)
                dispatch('snackbar/setSnackbar', {
                    text:'Thanks for Adding A review for this Product',
                    type:'success'
                }, {root:true})
                commit('SET_BTN_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
            }
        },
        // delete product
        deleteProduct: async ({dispatch, rootState},id) => {
            try {
                await Axios.delete('/api/products/'+id)
                dispatch('alert/setAlert', {
                    text:'Product deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                let newData = {limit:1000}
                let user = rootState.auth.user
                if(user.role == 'publisher'){
                    newData.user = user._id
                }
                dispatch('fetchProducts', newData)
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update product
        updateProduct: async ({state , dispatch , commit, rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                // some settings to update the product
                let product = state.product
                if(!product.avatar){
                    delete product.avatar
                }
                if(product.category._id){
                    product.category = product.category._id
                }
                if(product.user._id){
                    product.user = product.user._id
                }
                const id = state.product._id
                delete state.product.reviews
                delete state.product.buyers
                const payload = formData(state.product);
                await Axios.put('/api/products/'+id, payload)
                dispatch('alert/setAlert', {
                    text:'Product updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_PRODUCT')
                let newData = {limit:1000}
                let user = rootState.auth.user
                if(user.role == 'publisher'){
                    newData.user = user._id
                }
                dispatch('fetchProducts', newData)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
            commit('SET_AVATAR_URL', null)
        },
        // set edit product
        setEditProduct: ({commit}, payload) => {
            commit('SET_EDIT_PRODUCT', payload)
            let avatarUrl = payload.avatar ? `http://localhost:5000/uploads/products/${payload.avatar}` : null
            // set avatar url
            commit('SET_AVATAR_URL', avatarUrl)
            // set avatar to null
            commit('SET_AVATAR', null)
        },
        // set default product
        setDefaultProduct: ({commit}) => {
            commit('SET_DEFAULT_PRODUCT')
            commit('SET_AVATAR_URL', null)
        },
        // upload Image
        uploadImage: ({state, commit}) => {
            let image = state.product.avatar
            if(image){
                if(image.type.startsWith('image') && image.size <= 2048000){
                    const fileReader = new FileReader()
                    fileReader.addEventListener('load', () => {
                        const result = fileReader.result
                        commit('SET_AVATAR_URL', result)
                    })
                    fileReader.readAsDataURL(image)
                }
            }else{
                commit('SET_AVATAR_URL', null)
            }
            
        },
        topSellingProducts: async ({commit}) => {
            try {
                let data = await Axios.get('/api/products/topSellingProducts')
                commit('SET_TOP_SELLING_PRODUCTS', data.data.products)
            } catch (error) {
                console.log(error.response)
            }
        }
    }
}