import { mapActions, mapState } from "vuex";
import CustomAlert from '@/components/notifications/CustomAlert'

export default {
    data(){
        return {
            loading:false,
            alert:{
                text:'',
                type:'success',
                show:false,
            },
        }
    },
    methods: {
        ...mapActions('auth', ['register', 'login', 'forgotPassword', 'updatePassword'])
    },
    computed: {
        ...mapState(['auth'])
    },
    components:{
        CustomAlert
    }
}