import router from '../../router'
import setToken from '../../utils/SetToken'
import setErr from '../../utils/ResponseError'
import Axios from 'axios'

export default {
    namespaced:true,
    state:{
        user:null,
        loading:false
    },
    getters:{
        // check if any user loggedIn
        isLoggedIn(state){
            return !!state.user
        },
        // authorize rule for any route
        isAuthorized: (state) => role => {
            if(!role){
                return true
            }
            return state.user.role == role
        },
        // get the auth user
        getAuthUser: (state) => {
            return state.user
        }
    },
    mutations:{
        // set user mutation
        SET_USER : (state, payload) => {
            // the auth user
            state.user = payload
            // set the auth user to the local storage
            localStorage.setItem('user', JSON.stringify(payload))
            // set token after user logged in or register
            setToken(payload.token)
        },
        // set loading
        SET_LOADING : (state,pyload) => {
            state.loading = pyload
        }
    },
    actions:{
        // register action
        register : async ({dispatch,commit}, payload) => {
            // check for cart items
            const items = JSON.parse(localStorage.getItem('cart'))
            // check for cart items if they exist
            if(items){
                payload.items = items
            }
            try {
                // send request to backend api
                const data = await Axios.post('/api/auth/register', payload)
                // set user if credentials are right
                commit('SET_USER', data.data.data)
                // empty the local storage cart after registration
                dispatch('cart/emptyCart', null, {root:true})
                // set cart products with auth user cart products
                dispatch('cart/setCart', null, {root:true})
                // push the user to dashboard
                router.push({name:'dashboard'})
                // set success alert
                const alert = {
                    text:'',
                    type:'success',
                    show:false
                }
                // return success alert
                return alert
            } catch (error) {
                // set error alert
                const alert = {
                    text:setErr(error),
                    type:'error',
                    show:true
                }
                // return error alert
                return alert
            }
        },
        // login action
        login: async ({ dispatch, commit, state}, payload) => {
            try {
                // check for cart items
                const items = JSON.parse(localStorage.getItem('cart'))
                // check for cart items if they exist
                if(items){
                    payload.items = items
                }
                // send request to backend api
                const data = await Axios.post('/api/auth/login', payload)
                // set auth user if login credentials are right
                commit('SET_USER', data.data.data)
                // empty local storage cart after login
                dispatch('cart/emptyCart', null, {root:true})
                // set cart products with the user cart products
                dispatch('cart/setCart', null, {root:true})
                // send the user to dashboard
                router.push({name:'dashboard'})
                // set success alert
                const alert = {
                    text:'',
                    type:'success',
                    show:false
                }
                // retur success alert
                return alert
            } catch (error) {
                // set error alert
                const alert = {
                    text:setErr(error),
                    type:'error',
                    show:true
                }
                // return error alert
                return alert
            }
        },
        // logout action
        logout: ({dispatch}) => {
            // remove the auth user from local storage
            localStorage.removeItem('user')
            // remove the cart products
            dispatch('cart/emptyCart', null, {root:true})
            // set token to false
            setToken(false)
            // reload the app to mutate the vuex store to its initial state
            location.reload()
        },
        // forgot password action
        forgotPassword: async ({}, payload) => {
            try {
                // send request to backend api
                await Axios.post('/auth/forgotPassword', payload)
                // set success alert
                const alert = {
                    text:'A Mail send to your email plz check it',
                    type:'success',
                    show:true
                }
                // return success alert
                return alert
            } catch (error) {
                // set error alert
                const alert = {
                    text:setErr(error),
                    type:'error',
                    show:true
                }
                // return error alert
                return alert
            }
        },
        // update password fucntin
        updatePassword: async ({},payload) => {
            try {
                // send request to backend api
                const data = await Axios.post(`/auth/updatePassword/${payload.token}`, payload)
                // set success alert
                const alert = {
                    text:'Your Password is Updated Plz go to Login',
                    type:'success',
                    show:true
                }
                // return success alert
                return alert
            } catch (error) {
                // set error alert
                const alert = {
                    text:setErr(error),
                    type:'error',
                    show:true
                }
                // return error alert
                return alert
            }
        },
        // set user action
        setUser: ({commit}, payload) => {
            // set user mutation
            commit('SET_USER', payload)
        }
    }
}