import setErr from '../../utils/ResponseError'
import formData from '../../utils/DataForm'
import Axios from 'axios'

export default {
    namespaced:true,
    state:{
        path:process.env.NODE_ENV == 'development' ? 'http://localhost:5000/uploads/sliders' : location.origin+'/uploads/sliders',
        sliders:[],
        slider:{
            heading:'',
            image:null,
            order:''
        },
        defaultSlider:{
            heading:'',
            image:null,
            order:''
        },
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,
        imageUrl:null
    },
    getters:{
        getSlider: state => id => {
            return state.sliders.filter(slider => slider._id == id)
        }
    },
    mutations:{
        SET_SLIDERS: (state, payload) => {
            state.sliders = payload
        },
        SET_SLIDER: (state, payload) => {
            state.slider = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_SLIDER: (state) => {
            state.slider = Object.assign({}, state.defaultSlider)
        },
        SET_EDIT_SLIDER: (state,payload) => {
            state.slider = Object.assign({}, payload)
        },
        SET_IMAGE_URL: (state, payload) => {
            state.imageUrl = payload
        },
        SET_IMAGE: (state, payload) =>{
            state.slider.image = payload
        } 
    },
    actions:{
        // fetch all sliders
        fetchSliders: async ({dispatch,commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/sliders')
                commit('SET_SLIDERS', data.data.sliders)
                commit('SET_LOADING', false)
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'success',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // add slider
        addSlider: async ({state ,dispatch , commit, rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = state.slider
                const slider = formData(data);
                await Axios.post('/api/sliders' ,slider)
                dispatch('alert/setAlert', {
                    text:'Slider added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_SLIDER')
                dispatch('fetchSliders')
            } catch (error) {
                console.log(error.response)
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete slider
        deleteSlider: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/sliders/'+id)
                dispatch('alert/setAlert', {
                    text:'Slider deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchSliders')
            } catch (error) {
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update slider
        updateSlider: async ({state , dispatch , commit, rootState}) => {
            try {
                commit('SET_BTN_LOADING', true)
                let data = state.slider
                if(!data.image){
                    delete data.image
                }
                const slider = formData(data)
                await Axios.put('/api/sliders/'+state.slider._id,slider)
                dispatch('alert/setAlert', {
                    text:'Slider updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_SLIDER')
                dispatch('fetchSliders')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit slider
        setEditSlider: ({commit,state}, payload) => {
            commit('SET_EDIT_SLIDER', payload)
            let imageUrl = payload.image ? `${state.path}/${payload.image}` : null
            // set image url
            commit('SET_IMAGE_URL', imageUrl)
            // set image to null
            commit('SET_IMAGE', null)
        },
        // set default slider
        setDefaultSlider: ({commit}) => {
            commit('SET_DEFAULT_SLIDER')
            commit('SET_IMAGE_URL', null)
        },
        // upload Image
        uploadImage: ({state, commit}) => {
            let image = state.slider.image
            if(image){
                if(image.type.startsWith('image') && image.size <= 2048000){
                    const fileReader = new FileReader()
                    fileReader.addEventListener('load', () => {
                        const result = fileReader.result
                        commit('SET_IMAGE_URL', result)
                    })
                    fileReader.readAsDataURL(image)
                }
            }else{
                commit('SET_IMAGE_URL', null)
            }
            
        }
    }
}