<template>
  <!-- <v-row> -->
      <!-- <v-col> -->
        <v-form ref="addressForm" v-model="validForm">
            <v-card>
                <v-card-text>
                    <v-toolbar dark color="dark">
                        <v-toolbar-title class="mx-auto">
                            {{ $t('checkout_page.address_heading') }}
                        </v-toolbar-title>
                    </v-toolbar>
                    <v-container>
                        <v-row>
                            <v-col cols="12">
                                <v-text-field
                                    v-model="checkout.address.address1"
                                    :label="$t('checkout_page.address_1')"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                            <v-col cols="12">
                                <v-text-field
                                    v-model="checkout.address2"
                                    :label="$t('checkout_page.address_2')"
                                ></v-text-field>
                            </v-col>
                            <v-col>
                                <v-text-field
                                    v-model="checkout.address.country"
                                    :label="$t('checkout_page.country')"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                            <v-col>
                                <v-text-field
                                    v-model="checkout.address.state"
                                    :label="$t('checkout_page.state')"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                            <v-col>
                                <v-text-field
                                    v-model="checkout.address.city"
                                    :label="$t('checkout_page.city')"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                            <v-col>
                                <v-text-field
                                    v-model="checkout.address.zip"
                                    :label="$t('checkout_page.zip')"
                                    type="number"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                            <v-col cols="12">
                                <v-text-field
                                    v-model="checkout.address.phone"
                                    :label="$t('checkout_page.phone')"
                                    type="number"
                                    :rules="[rules.required]"
                                ></v-text-field>
                            </v-col>
                        </v-row>
                    </v-container>
                </v-card-text>
                <v-card-actions>
                    <v-btn
                        color="dark"
                        @click="$emit('changeE1')"
                        :disabled="!validForm"
                        dark
                        >
                        {{ $t('checkout_page.confirm_order') }}
                    </v-btn>

                    <v-btn text @click="$router.push({name:'cart'})">{{ $t('checkout_page.cancel') }}</v-btn>
                </v-card-actions>
            </v-card>
        </v-form>
      <!-- </v-col> -->
  <!-- </v-row> -->
</template>

<script>
import { mapState } from 'vuex'
import formValidations from '@/mixins/formValidations'
export default {
    mixins:[formValidations],
    data(){
        return {
            validForm:false
        }
    },
    computed:{
        ...mapState(['checkout'])
    }
}
</script>

