import setErr from '../../utils/ResponseError'
import { i18n } from '../../main'
import en from '../../localization/en.json'
import Axios from 'axios'

export default {
    namespaced:true,
    state:{
        langs:[
            {name:'English', locale:'en'}
        ],
        translations:{
            en
        },
        siteLang:'en',
        fallbackLocale:'en',
        lang:{
            name:'',
            locale:''
        },
        defaultLang:{
            name:'',
            locale:''
        },
        fallbackLocale:'en',
        dialog:false,
        loading:false,
        loadingBtn:false,
        edit:false,
    },
    getters:{
        getLang: state => id => {
            return state.langs.filter(lang => lang._id == id)
        },
        getTranslation: state => locale => {
            let trans = state.translations[locale]
            return trans
        }
    },
    mutations:{
        SET_LANGS: (state, payload) => {
            state.langs = payload
        },
        SET_SITE_LANG: (state, payload) => {
            state.siteLang = payload
        },
        SET_LANG: (state, payload) => {
            if(payload){
                state.lang.locale = payload
            }else{
                state.lang.locale = state.siteLang
            }
            
        },
        SET_TRANSLATIONS: (state, payload) => {
            state.translations = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        },
        SET_LANG_TO_LOCAL_STORAGE: (state,payload) => {
            localStorage.setItem('lang', JSON.stringify(state.siteLang))
        },
        SET_EDIT: (state, payload) => {
            state.edit = payload
        },
        SET_DIALOG: (state, payload) => {
            state.dialog = payload.dialog
            state.edit = payload.edit
        },
        SET_DEFAULT_LANG: (state) => {
            state.lang = Object.assign({}, state.defaultLang)
        },
        SET_EDIT_LANG: (state,payload) => {
            state.lang = Object.assign({}, payload)
        },
        SET_LOCALE: (state) => {
            i18n.locale = state.siteLang
        },
        SET_LOCALE_MESSAGES: (state) => {
            i18n.setLocaleMessage(state.siteLang,state.translations[state.siteLang])
        }
    },
    actions:{
        // set language action
        setLang: async ({commit}, payload) => {
            commit('SET_SITE_LANG', payload)
            commit('SET_LANG_TO_LOCAL_STORAGE')
            commit('SET_LOCALE')
            commit('SET_LOCALE_MESSAGES')
        },
        // fetch all languages
        fetchLangs: async ({commit}) => {
            try {
                commit('SET_LOADING', true)
                const data = await Axios.get('/api/languages')
                let languages = data.data.languages
                let translations = data.data.translations
                commit('SET_LANGS', languages)
                commit('SET_LOADING', false)
                commit('SET_TRANSLATIONS', translations)
                // commit('SET_LOCALE')
                commit('SET_LOCALE_MESSAGES')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                commit('SET_TRANSLATIONS', en)
                commit('SET_LANGS', {name:'English', locale:'en'})
            }
            
        },
        // add langs
        addLang: async ({state ,dispatch , commit}) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.post('/api/languages' ,state.lang)
                dispatch('alert/setAlert', {
                    text:'Language added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_LANG')
                dispatch('fetchLangs')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // delete lang
        deleteLang: async ({dispatch},id) => {
            try {
                await Axios.delete('/api/languages/'+id)
                dispatch('alert/setAlert', {
                    text:'Language deleted Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                dispatch('fetchLangs')
            } catch (error) {
                console.log(error.response)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
            }
        },
        // update lang
        updateLang: async ({state , dispatch , commit, rootState},payload) => {
            try {
                commit('SET_BTN_LOADING', true)
                await Axios.put('/api/languages/'+state.lang._id,state.lang)
                dispatch('alert/setAlert', {
                    text:'Language updated Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                commit('SET_DIALOG', {dialog:false,edit:false})
                commit('SET_DEFAULT_LANG')
                dispatch('fetchLangs')
            } catch (error) {
                commit('SET_BTN_LOADING', false)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dialog'
                } , {root:true})
            }
        },
        // set dialog
        setDialog: async({commit}, payload) => {
            commit('SET_DIALOG', payload)
        },
        // set edit lang
        setEditLang: ({commit}, payload) => {
            commit('SET_EDIT_LANG', payload)
        },
        // set default lang
        setDefaultLang: ({commit}) => {
            commit('SET_DEFAULT_LANG')
        }
    }
}