<template>
  <div>
      <v-row v-if="product.product">
        <v-col>
          <v-card class="my-5">
            <v-toolbar>
              <v-toolbar-title>
                {{ $t('product_page.reviews_heading') }}
              </v-toolbar-title>
            </v-toolbar>
            <div v-if="productReviewsCount(product.product.reviews) > 0">
              <v-card-text v-for="review in product.product.reviews" :key="review.id">
            <v-avatar
                  size="36px"
                >
                  <img
                    v-if="review.user.avatar"
                    alt="Avatar"
                    :src="setting.settings.images.url+'/users/'+review.user.avatar"
                  >
                </v-avatar>
                {{ review.user.name }}
            <v-rating
              :value="review.rating"
              background-color="white"
              color="yellow accent-4"
              half-increments
              size="18"
              readonly
            ></v-rating>
            
            <div v-if="review.feedback">
              {{review.feedback}}
            </div>

            <div>
              <small class="grey--text mt-5">{{review.date | formatDate}}</small>
            </div>
            <v-divider class="my-5"></v-divider>
            </v-card-text>
            </div>
            <div v-else>
              <v-card-text>
                {{ $t('product_page.no_reviews') }}
              </v-card-text>
              <v-divider class="mt-5"></v-divider>
            </div>
            <v-card-actions>
              <v-btn @click="leaveReview = true" color="success" dark>
                {{ $t('product_page.leave_review') }}
              </v-btn>
            </v-card-actions>
          </v-card>
        </v-col>
      </v-row>
      <v-row v-if="!product.loading && leaveReview">
        <v-col>
          <v-card
            class="elevation-16 mx-auto"
          >
            <v-card-title
              class="headline"
              primary-title
            >
              {{ $t('product_page.rate_product_heading') }}
            </v-card-title>
            <v-card-text>
              {{ $t('product_page.rate_product_text') }}

              <div class="text-center mt-12">
                <v-rating
                  v-model="review.rating"
                  color="yellow darken-3"
                  background-color="grey darken-1"
                  empty-icon="$ratingFull"
                  half-increments
                  hover
                ></v-rating>
              </div>
              <v-text-field
                v-model="review.feedback"
                :label="$t('product_page.write_feedback')"
              >
              </v-text-field>
            </v-card-text>
            <v-divider></v-divider>
            <v-card-actions class="justify-space-between">
              <v-btn
                color="primary"
                text
                @click="reviewAdd"
                :loading="product.loadingBtn"
                :disabled="review.rating == 0"
              >
                {{ $t('product_page.rate_now') }}
              </v-btn>
            </v-card-actions>
          </v-card>
        </v-col>
      </v-row>
  </div>
</template>

<script>
import { mapActions, mapState, mapGetters } from 'vuex'
import moment from 'moment'
export default {
    data(){
        return{
          leaveReview:false,
          review:{
              rating:0,
              feedback:''
          }
        }
    },
    computed: {
    ...mapState(['product', 'auth', 'setting']),
    ...mapGetters('product', ['productReviewsCount'])
    },
    methods: {
        ...mapActions('product', ['fetchProduct', 'addReview']),
        async reviewAdd(){
        const payload = {
            productId: this.product.product._id,
            userId:this.auth.user ? this.auth.user._id : null,
            review:this.review,
            date:Date.now()
        }
        await this.addReview(payload)
        }
    },
    filters:{
        formatDate(value) {
            if (value) {
                return moment(String(value)).format('MM/DD/YYYY hh:mm')
            }
        }
    }
}
</script>

