import setErr from '../../utils/ResponseError'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        translations:{},
        locale:'en',
        loading:false,
        loadingBtn:false,
    },
    getters:{
        
    },
    mutations:{
        SET_TRANSLATIONS: (state, payload) => {
            state.translations = payload
        },
        SET_LOCALE: (state, payload) => {
            state.locale = payload
        },
        SET_LOADING: (state,payload) => {
            state.loading = payload
        },
        SET_BTN_LOADING: (state,payload) => {
            state.loadingBtn = payload
        }
    },
    actions:{
        // set Default Translation
        setTranslations: async ({commit, state, rootState}) => {
            try {
                commit('SET_LOADING', true)
                let translations = rootState.lang.translations[state.locale]
                commit('SET_TRANSLATIONS', translations)
                commit('SET_LOADING', true)
            } catch (error) {}
        },
        // update Translations
        updateTranslations: async ({dispatch, commit, state}) => {
            try {
                commit('SET_BTN_LOADING', true)
                const data = await Axios.put('/api/translations/'+state.locale,state.translations)
                dispatch('alert/setAlert', {
                    text:'Language added Successfully',
                    type:'success',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
                dispatch('lang/fetchLangs', null, {root:true})
            } catch (error) {
                console.log(error.response)
                dispatch('alert/setAlert', {
                    text:setErr(error),
                    type:'error',
                    display:'dataTable'
                } , {root:true})
                commit('SET_BTN_LOADING', false)
            }
        }
    }
}