<script>
import { HorizontalBar } from 'vue-chartjs'
import { mapState } from 'vuex'
export default {
    data(){
        return {
            data:{},
            options:{}
        }
    },
    computed:{
      ...mapState(['report'])
    },
    extends:HorizontalBar,
    mounted(){
      this.renderChart({
        labels: this.report.records.yearRecords.months,
        datasets: [
          {
            label: this.$t('dashboard_page.annual_orders_record'),
            backgroundColor: '#1cc88a',
            data: this.report.records.yearRecords.orders
          }
        ]
    })
    }
}
</script>

