<template>
  <v-container>
    <v-row>
      <v-col>
        <v-card
          class="my-5 py-3 text-center justify-center"
        >
                <h3 class="text-center mx-auto">
                    
                        {{ product.product.name }}
                    
                </h3>

                <v-card-text>

                <div class="my-4 subtitle-1">
                    <h3 right class="mr-3 primary--text">${{ product.product.price }}</h3>
                </div>

                <div>
                    {{ product.product.excerpt }}
                </div>
                </v-card-text>
            </v-card>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <v-stepper v-model="e1">
          <v-container>
              <v-stepper-header>
            <v-stepper-step color="dark" step="1">{{ $t('checkout_page.payment') }}</v-stepper-step>
          </v-stepper-header>

          <v-stepper-items>
            <v-stepper-content step="1">
              <DigitalPayment/>
            </v-stepper-content>
          </v-stepper-items>
          </v-container>
        </v-stepper>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { mapGetters, mapActions, mapState } from 'vuex'
import DigitalPayment from '@/components/cart/DigitalPayment'
export default {
    data(){
        return {
            e1:1,
            
        }
    },
    components:{
      DigitalPayment
    },
    methods:{
      ...mapActions('product', ['fetchProduct'])
    },
    computed:{
      ...mapState(['product'])
    },
    created(){
      this.product = this.fetchProduct(this.$route.params.productId)
    }
}
</script>

