<template>
<div class="auth-layout primary">
    <v-container
        class="fill-height py-0"
        fluid
    >
        <v-row
            align="center"
            justify="center"
            class="auth-layout-row"
        >
            <v-col cols="10" class="mx-auto white dark--text">
                <v-row class="auth-row" align="center" justify="center">
                    <v-col cols="6" class="img-col d-none d-sm-block">
                        <!-- <v-card> -->
                            <v-img 
                                class="auth-img"
                                :src="getImage('update password')"
                            ></v-img>
                        <!-- </v-card> -->
                    </v-col>
                    <v-col class="px-10 form-col">
                        <v-form @submit.prevent="submitForm" v-model="validForm">
                    <div class="text-center my-5 form-header">
                        {{ $t('auth_page.update_page_heading') }}
                        </div>
                                
                                <div class="my-3">
                                    <CustomAlert :alert="alert"/>
                                </div>
                            <v-text-field
                                id="password"
                                :label="$t('auth_page.password_label')"
                                v-model="password"
                                prepend-icon="mdi-lock"
                                :append-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
                                @click:append="showPassword = !showPassword"
                                :type="showPassword ? 'text' : 'password'"
                                :rules="passwordRules"
                                solo
                                rounded
                            />
                            <v-text-field
                                id="confirmPassword"
                                :label="$t('auth_page.confirm_passwrd')"
                                v-model="confirmPassword"
                                prepend-icon="mdi-lock"
                                :append-icon="showConfirmPassword ? 'mdi-eye' : 'mdi-eye-off'"
                                @click:append="showConfirmPassword = !showConfirmPassword"
                                :type="showConfirmPassword ? 'text' : 'password'"
                                :rules="ConrimPasswordRules"
                                solo
                                rounded
                            />
                        
                            <v-btn type="submit" block rounded color="indigo" :disabled="!validForm" :dark="validForm" :loading="loading">
                                {{ $t('auth_page.update_password') }}
                            </v-btn>

                            <v-divider class="my-5"></v-divider>
                            <div class="text-center mb-5">
                                        <div>
                                            <small><router-link :to="{name: 'register'}">{{ $t('auth_page.create_account_link') }}</router-link></small>
                                        </div>
                                        <div>
                                            <small><router-link :to="{ name: 'login' }">{{ $t('auth_page.already_have_account_link') }}</router-link></small>
                                        </div>
                                    </div>
                        
                </v-form>
                    </v-col>
                </v-row>
            </v-col>
      </v-row>


  </v-container>
  </div>
</template>

<script>
import auth from '@/mixins/auth'
import { mapGetters } from 'vuex'
export default {
    mixins:[auth],
    data(){
        return {
            validForm:false,
            password:'',
            confirmPassword:'',
            showPassword:false,
            showConfirmPassword:false,
            passwordRules:[
                value => !!value || 'Please Type Password',
                value => value.length > 7 || 'Password Must Be Atleast 8 Characters'
            ],
            ConrimPasswordRules:[
                value => !!value || 'Please Type Password',
                value => this.password == value || 'Password Not Matched'
            ]
        }
    },
    computed:{
        ...mapGetters('image', ['getImage'])
    },
    methods: {
        async submitForm(){
            try {
                this.loading = true
                this.alert.show = false
                this.alert = await this.updatePassword({
                    password:this.password,
                    token:this.$route.params.token
                })
                this.loading = false
            } catch (error) {
                this.loading = false
            }
            
        }
    },
}
</script>

