<template>
  <v-container>
    <v-btn color="red" @click="openDialog" fixed bottom right fab dark class="mb-2">
      <v-icon>mdi-plus</v-icon>
    </v-btn>
    <v-row>
      <v-col>
        <BaseAlert v-if="alert.display == 'dataTable'"/>
      </v-col>
    </v-row>
    <v-row>
      <v-col>
        <!-- show-select -->
        <v-data-table
          v-model="selected"
          :headers="headers"
          :items="cat.cats"
          :search="search"
          :loading="cat.loading"
          item-key="_id"
          :single-select="singleSelect"
          
          sort-by="name"
          class="elevation-1"
        >
          <template v-slot:top>
            <v-toolbar color="light">
              <v-toolbar-title class="mx-auto">{{ $t('dashboard_pages_heading.categories') }}</v-toolbar-title>
              <v-divider
                class="mx-4"
                inset
                vertical
              ></v-divider>
              <v-spacer></v-spacer>
              <v-text-field 
                class="mt-5"
                :label="$t('dashboard_input_labels.search')"
                v-model="search"
                append-icon="mdi-magnify"
              >
              </v-text-field>
              <v-dialog v-model="cat.dialog" max-width="500px">
                <v-card>
                  <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
                    <v-card-title>
                      <span class="headline">
                        {{
                           !cat.edit ? $t('dashboard_modal.new_item')+' '+ $t('dashboard_modal.category') : $t('dashboard_modal.edit_item')+' '+$t('dashboard_modal.category') 
                        }}
                      </span>
                    </v-card-title>
                    <v-card-text>
                      <v-container>
                        <template>
                          <v-row>
                          <v-col>
                            <BaseAlert v-if="alert.display == 'dialog'"/>
                          </v-col>
                        </v-row>
                        </template>
                        <v-row>
                          <v-col>
                              <v-text-field
                                  :label="$t('dashboard_input_labels.name')"
                                  v-model="cat.cat.name"
                                  prepend-icon="mdi-shape"
                                  type="text"
                                  :rules="[rules.required]"
                                  name="name"
                              />
                          </v-col>
                        </v-row>
                      </v-container>
                    </v-card-text>
                    <v-card-actions>
                      <v-spacer></v-spacer>
                      <v-btn color="blue darken-1" dark @click="close">{{ $t('dashboard_modal.cancel_btn') }}</v-btn>
                      <v-btn color="blue darken-1" :disabled="!validForm" :loading="cat.loadingBtn" :dark="validForm" type="submit" >{{ $t('dashboard_modal.save_btn') }}</v-btn>
                    </v-card-actions>
                  </v-form>
                </v-card>
              </v-dialog>
            </v-toolbar>
          </template>
          <template v-slot:item.actions="{ item }">
            <v-icon
              small
              color="success"
              class="mr-2"
              @click="editItem(item)"
            >
              mdi-pencil
            </v-icon>
            <v-icon
              color="error"
              @click="deleteItem(item)"
            >
              mdi-delete
            </v-icon>
          </template>
        </v-data-table>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: (vm) => ({
      search:'',
      validForm:false,
      singleSelect:false,
      selected:[],
      headers: [
        {
          text: vm.$t('dashboard_datatable.name'),
          align: 'start',
          value: 'name',
        },
        { text: vm.$t('dashboard_datatable.actions'), value: 'actions', sortable: false },
      ],
    }),
    mixins:[formValidations],
    computed: {
      ...mapState(['cat' , 'alert']),
      ...mapGetters('cat',['getCat'])
    },

    watch: {
      dialog (val) {
        val || this.close()
      },
    },

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('cat', ['fetchCats', 'addCat', 'setDialog', 'deleteCat', 'updateCat', 'setEditCat', 'setDefaultCat']),
      // initialize the data table
      async initialize () {
        await this.fetchCats()
      },
      // edit item
      async editItem (item) {
        this.setEditCat(item)
        this.setDialog({dialog:true,edit:true})
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // delete item
      async deleteItem (item) {
        if(confirm('Are you sure you want to delete this category?')){
          await this.deleteCat(item._id)
        }
      },
      // open dialog
      openDialog(){
        this.setDialog({dialog:true,edit:false})
        this.setDefaultCat()
        this.$store.dispatch('alert/removeAlert', {root:true})
      },
      // close dialog
      close () {
        this.setDialog({dialog:false,edit:false})
        this.setDefaultCat()
        this.$refs.modalForm.resetValidation()
      },
      // submit the form
      async save () {
        if (this.cat.edit) {
          await this.updateCat()
        } else {  
          await this.addCat()
        }
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>