<template>
  <div>
      <Carousel />
      <v-row class="my-5">
        <v-col class="text-center my-5">
          <h1 class="indigo--text">{{ $t('products_page.products_heading') }}</h1>
          <h1 class="indigo--text"></h1>
          <v-divider></v-divider>
        </v-col>
      </v-row>
        <v-row v-if="!product.loading">
          <Products v-for="product in product.products" :key="product._id" :product="product"/>
        </v-row>
        <div v-else class="text-center my-5">
          <Loading />
        </div>
        <v-row>
          <Pagination />
        </v-row>
        <div v-if="product.count == 0 && !product.loading" class="text-center my-5">
           {{ $t('products_page.no_products') }}
        </div>
     
  </div>
</template>

<script>
import { mapActions, mapState } from 'vuex'
import Products from '@/components/pages/products/Products'
import Pagination from '@/components/pages/products/Pagination'
import Carousel from '@/components/pages/products/Carousel'
import Loading from '@/components/Loading/Loading4'
export default {
  data(){
    return {
      page:1,
      length:1
    }
  },
  components:{
    Products,
    Pagination,
    Carousel,
    Loading
  },
  computed: {
    ...mapState(['product'])
  },
  methods: {
    ...mapActions('product', ['fetchProducts'])
  },
  mounted() {
    this.fetchProducts(this.$route.query)
  },
}
</script>

