<template>
  <div class="home-layout">
    <Header v-if="showHeader"/>
    <v-content>
      <div :class="containerClass">
        <v-row>
          <v-col class="col-12 col-md-3 col-sm-3" v-if="showSidebar">
            <Sidebar/>
          </v-col>
          <v-col :class="mainContentClass">
            <Main />
          </v-col>
        </v-row>
      </div>
    </v-content>
    <Footer v-if="showFooter"/>
  </div>
</template>

<script>
import Header from './pages/Header'
import Main from './pages/Main'
import Sidebar from './pages/Sidebar'
import Footer from './pages/Footer'
export default {
  data: () => ({
    //
  }),
  computed:{
    showFooter(){
      if(this.$route.meta.footer == false){
        return this.$route.meta.footer
      }else{
        return true
      }
      return true
    },
    showSidebar(){
      if(this.$route.meta.sidebar == false){
        return this.$route.meta.sidebar
      }else{
        return true
      }
      return true
    },
    showHeader(){
      if(this.$route.meta.header == false){
        return this.$route.meta.header
      }else{
        return true
      }
      return true
    },
    containerClass(){
      if(this.$route.meta.sidebar == false){
        return  ['']
      }else{
        return ['container']
      }
    },
    mainContentClass(){
      if(this.$route.meta.sidebar == false){
        return ['col-12']
      }else{
        return ['col-md-9', 'col-sm-9']
      }
    }
  },
  components:{
    Header,
    Main,
    Sidebar,
    Footer
  }
};
</script>

