<template>
<div>
  <div :style="{height:setHeight}"></div>
  <v-footer
    dark
    color="dark"
    padless
    absolute
    :style="{'margin-top':setHeight}"
  >
  <div ref="mainFooter" :style="{width:'100%'}">
    <v-row>
      <v-col>
        <v-card
      flat
      tile
      class="text-center"
    >
      <v-card-text>
        <v-btn
          v-for="(icon, i) in icon.icons"
          :key="i"
          class="mx-4 white--text"
          icon
          link
          :href="icon.url"
          target="_blank"
        >
          <v-icon size="24px">{{ icon.icon }}</v-icon>
        </v-btn>
      </v-card-text>

      <v-card-text class="white--text pt-0">
        {{ $t('app_footer.text') }}
      </v-card-text>

      <v-divider></v-divider>

      <v-card-text class="white--text">
        {{ new Date().getFullYear() }} — <strong>{{ $t('app_footer.copyright') }}</strong>
      </v-card-text>
    </v-card>
      </v-col>
    </v-row>
    </div>
  </v-footer>
</div>
  
</template>

<script>
  import { mapState, mapActions } from 'vuex'
  export default {
    data: () => ({
      footerHeight:'',
      icons: [
        'mdi-facebook',
        'mdi-twitter',
        'mdi-google-plus',
        'mdi-linkedin',
        'mdi-instagram',
      ],
    }),
    computed: {
      ...mapState(['icon']),
      setHeight(){
        return this.footerHeight
      }
    },
    mounted() {
      this.getFooterHeight(),
      this.fetchIcons()
    },
    methods: {
      ...mapActions('icon', ['fetchIcons']),
      getFooterHeight(){
        this.footerHeight = this.$refs.mainFooter.clientHeight+30+'px'
      }
    },
  }
</script>

<style lang="css" scoped>
  .col{
    padding: 0;
  }
  .v-footer{
    margin-top: 500px;
  }
</style>