<template>
    <div class="auth-layout primary">
    <v-container
        class="fill-height py-0"
        fluid
    >
        <v-row
            align="center"
            justify="center"
            class="auth-layout-row"
        >
            <v-col cols="10" class="mx-auto white dark--text">
                <v-row class="auth-row" align="center" justify="center">
                    <v-col cols="6" class="img-col d-none d-sm-block">
                        <!-- <v-card> -->
                            <v-img 
                                class="auth-img"
                                :src="getImage('forgot password')"
                            ></v-img>
                        <!-- </v-card> -->
                    </v-col>
                    <v-col class="px-10 form-col">
                        <v-form @submit.prevent="submitForm" v-model="validForm">
                    
                        
                            <div class="my-5">
                                <div class="text-center form-header mb-3">
                                    {{ $t('auth_page.forgot_page_heading') }}
                                </div>
                            <div class="text-center mb-7">
                                {{ $t('auth_page.forgot_page_text') }}
                            </div>
                            </div>
                                
                                <div class="my-3">
                                    <CustomAlert :alert="alert"/>
                                </div>
                        
                            <v-text-field 
                                :label="$t('auth_page.email_label')"
                                v-model="resetEmail"
                                prepend-icon="mdi-email"
                                type="email"
                                :rules="resetEmailRules"
                                solo
                                rounded
                            />
                        
                        
                            <v-btn type="submit" block rounded color="indigo" :disabled="!validForm" :dark="validForm" :loading="loading">
                                {{ $t('auth_page.forgot_password') }}
                            </v-btn>
                        
                         <v-divider class="my-5"></v-divider>
                            <div class="text-center mb-5">
                                        <div>
                                            <small><router-link :to="{name: 'register'}">{{ $t('auth_page.create_account_link') }}</router-link></small>
                                        </div>
                                        <div>
                                            <small><router-link :to="{ name: 'login' }">{{ $t('auth_page.already_have_account_link') }}</router-link></small>
                                        </div>
                                        <div>
                                            <small><router-link :to="{ name: 'products' }">{{ $t('auth_page.go_back_to_shoping_link') }}</router-link></small>
                                        </div>
                                    </div>
                    
                </v-form>
                    </v-col>
                </v-row>
            </v-col>
      </v-row>


  </v-container>
  </div>
</template>

<script>
import auth from '@/mixins/auth'
import { mapGetters } from 'vuex'
export default {
    mixins:[auth],
    data(){
        return {
            resetEmail:'',
            validForm:'',
            resetEmailRules:[
                value => !!value || 'Please Type Your Email',
                value => /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/.test(value) || 'Please Add Valid Email'
            ],
        }
    },
    computed:{
        ...mapGetters('image', ['getImage'])
    },
    methods:{
        async submitForm(){
            try {
                this.loading = true
                this.alert.show = false
                this.alert = await this.forgotPassword({ email:this.resetEmail })
                this.loading = false
            } catch (error) {
                this.loading = false
            }
        }
    }
}
</script>

