<template>
  <v-row>
    <v-col md="10" sm="12" xs="12" cols="12" class="mx-auto">
      <v-card>
        <v-card-text>
          <stripe-elements
          ref="elementsRef"
          :pk="publishKey"
          :amount="product.product.price"
          @token="tokenCreated"
          @loading="loading = $event"
        >
        </stripe-elements>
        <v-card-actions class="text-center">
          <v-btn class="mx-auto" :loading="checkout.loadingBtn" color="dark" dark @click="submit">{{ $t('checkout_page.pay') }} ${{product.product.price}}</v-btn>
        </v-card-actions>
        </v-card-text>
      </v-card>
    </v-col>
  </v-row>
</template>

<script>
import { mapActions, mapGetters, mapState } from 'vuex'
import { StripeElements } from 'vue-stripe-checkout';
export default {
  components: {
    StripeElements
  },
  data() {
    return {
      publishKey:'',
      loading: false,
      token: null,
      charge: null
    }
  },
  computed:{
    ...mapState(['auth', 'cart', 'checkout', 'setting', 'product']),
    ...mapGetters('cart', ['totalPrice']),
    getProduct(){
        const theProduct = this.product.product
        theProduct.quantity = 1
        return theProduct
    }
  },
  mounted() {
    this.getPublishKey()
  },
  methods: {
    ...mapActions('checkout', ['payWithCardDigital']),
    ...mapActions('setting', ['getKey']),
    getPublishKey: async function(){
      this.publishKey = await this.getKey({type: 'stripe'})
    },
    submit () {
      this.$refs.elementsRef.submit();
    },
    tokenCreated (token) {
      this.token = token;
      // for additional charge objects go to https://stripe.com/docs/api/charges/object
      this.charge = {
        source: token.card,
        amount: this.product.product.price,
        description: this.product.product.excerpt,
        token,
        user: this.auth.user._id,
        email:this.auth.user.email,
        products: [this.getProduct],
        product:this.getProduct
      }
      this.sendTokenToServer(this.charge);
    },
    sendTokenToServer (charge) {
      this.payWithCardDigital(charge)
    },
    mounted() {
      this.setting.settings.stripe.publishKey
    },
  }
}
</script>