<template>
 
            <v-card>
                <v-card-text>
                    <v-toolbar dark color="dark">
                        <v-toolbar-title class="mx-auto">
                            {{ $t('checkout_page.payment_heading') }}
                        </v-toolbar-title>
                    </v-toolbar>
                    <v-container>
                        <v-row>
                            <v-col class="text-center" v-if="paypalEnalble">
                                <v-btn color="dark" dark @click="paymentMethod = 'paypal'">
                                    {{ $t('checkout_page.pay_with_paypal') }}
                                </v-btn>
                            </v-col>
                            <v-col class="text-center" v-if="stripeEnalble">
                                <v-btn color="dark" dark @click="paymentMethod = 'stripe'">
                                    {{ $t('checkout_page.pay_with_card') }}
                                </v-btn>
                            </v-col>
                        </v-row>
                        <div v-if="stripeEnalble">
                            <DigitalStripeCheckout v-show="paymentMethod == 'stripe'" :product="product.product"/>
                        </div>
                        <div v-if="paypalEnalble">
                            <DigitalPaypalCheckout v-show="paymentMethod == 'paypal'" :product="product.product"/>
                        </div>
                    </v-container>
                </v-card-text>
                
            </v-card>
</template>

<script>
import { mapState } from 'vuex'
import DigitalStripeCheckout from '@/components/cart/DigitalStripeCheckout'
import DigitalPaypalCheckout from '@/components/cart/DigitalPaypalCheckout'
export default {
    data(){
        return {
            paymentMethod:false
        }
    },
    computed:{
        ...mapState(['setting', 'product']),
        paypalEnalble(){
            return this.setting.settings.payment.paypal
        },
        stripeEnalble(){
            return this.setting.settings.payment.stripe
        }
    },
    components:{
        DigitalStripeCheckout,
        DigitalPaypalCheckout
    }
}
</script>

