<template>
  <v-container>
    <v-form ref="modalForm" @submit.prevent="save" v-model="validForm">
    <v-card
    class="overflow-hidden"
    color="dark lighten-1"
    dark
  >
    <v-toolbar
      flat
      color="dark"
    >
      <v-icon>mdi-account</v-icon>
      <v-toolbar-title class="font-weight-light">{{ $t('dashboard_pages_heading.profile') }}</v-toolbar-title>
      <v-spacer></v-spacer>
      <v-btn
        color="success"
        fab
        small
        @click="isEditing = !isEditing"
      >
        <v-icon v-if="isEditing">mdi-close</v-icon>
        <v-icon v-else>mdi-pencil</v-icon>
      </v-btn>
    </v-toolbar>
    <v-card-text v-if="alert.display == 'dialog' || alert.display == 'dataTable'">
      <BaseAlert/>
    </v-card-text>
    <v-card-text>
      <v-row>
        <v-col cols="12" md="4" sm="4" class="mx-auto">
          <v-img
            v-if="user.avatarUrl"
            :src="user.avatarUrl"
            rounded
          ></v-img>
          <v-file-input
            v-model="user.user.avatar"
            append-icon="mdi-camera"
            :label="$t('dashboard_input_labels.update_avatar')"
            :rules="[rules.image,rules.imageSize]"
            @change="uploadImage"
            :disabled="!isEditing"
          >
          </v-file-input>
        </v-col>
      </v-row>
    </v-card-text>
    <v-card-text>
      <v-text-field
          :label="$t('dashboard_input_labels.name')"
          v-model="user.user.name"
          prepend-icon="mdi-account"
          type="text"
          :rules="[rules.required]"
          name="name"
          :disabled="!isEditing"
      />
      <v-text-field
          id="email"
          :label="$t('dashboard_input_labels.email')"
          name="email"
          v-model="user.user.email"
          prepend-icon="mdi-email"
          type="email"
          :rules="[rules.required , rules.email]"
          :disabled="!isEditing"
      />
      <v-switch
        v-if="auth.user.role == 'admin'"
        v-model="updateRole"
        :label="$t('dashboard_input_labels.update_role')"
        :disabled="!isEditing"
      ></v-switch>
      <v-select
        :items="roles"
        :label="$t('dashboard_input_labels.role')"
        prepend-icon="mdi-account"
        name="role"
        dense
        :rules="[rules.required]"
        v-model="user.user.role"
        :disabled="!updateRole"
      ></v-select>
      <v-switch
        v-model="updatePassword"
        :label="$t('dashboard_input_labels.update_password')"
        :disabled="!isEditing"
      ></v-switch>
      <v-text-field
        id="password"
        counter
        :label="$t('dashboard_input_labels.password')"
        name="password"
        v-model="user.user.password"
        prepend-icon="mdi-lock"
        :append-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
        @click:append="showPassword = !showPassword"
        :type="showPassword ? 'text' : 'password'"
        :rules="[rules.required , rules.minLength]"
        :disabled="!updatePassword"
      />
      <v-textarea
        counter
        :label="$t('dashboard_input_labels.bio')"
        v-model="user.user.bio"
        prepend-icon="mdi-shape"
        :disabled="!isEditing"
      ></v-textarea>
    </v-card-text>
    <v-divider></v-divider>
    <v-card-actions>
      <v-spacer></v-spacer>
      <v-btn
        color="success"
        @click="save"
        :disabled="!validForm && !isEditing" 
        :loading="user.loadingBtn"
      >
      {{ $t('dashboard_modal.update_btn') }}
      </v-btn>
    </v-card-actions>
  </v-card>
  </v-form>
  </v-container>
</template>


<script>
  import formValidations from '@/mixins/formValidations'
  import { mapActions, mapState, mapGetters } from 'vuex'
  export default {
    data: () => ({
      isEditing:false,
      search:'',
      updatePassword:false,
      updateRole:false,
      validForm:false,
      singleSelect:false,
      selected:[],
      showPassword:false,
      roles:['user', 'publisher', 'admin']
    }),
    computed: {
      ...mapState(['user' , 'alert', 'auth']),
    },
    mixins:[formValidations],

    created () {
      this.initialize()
    },

    methods: {
      ...mapActions('user', ['setDialog', 'setEditUser', 'setDefaultUser', 'uploadImage', 'updateProfile']),
      // initialize the data table
      async initialize () {
        this.setEditUser(this.auth.user)
      },
      // submit the form
      async save () {
        await this.updateProfile()
        this.$refs.modalForm.resetValidation()
      },
    },
  }
</script>