<template>
  <v-container>
    <v-row>
      <v-col>
        <v-card>
          <v-card-text>
            <div class="text-center">
              <div class="mx-auto" ref="paypal"></div>
            </div>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import {mapState, mapGetters, mapActions} from 'vuex'
// import image from "../assets/lamp.png"
export default {
  name: "HelloWorld",

  data: function() {
    return {
      loaded: false,
      clientId: ''
    }
  },
  computed:{
      ...mapState(['cart', 'auth', 'checkout', 'setting']),
      ...mapGetters('cart', ['totalPrice'])
  },
  mounted: async function() {

    this.clientId = await this.getKey({type: 'paypal'})

    const script = document.createElement("script");
    script.src =
      `https://www.paypal.com/sdk/js?client-id=${this.clientId}`;
    script.addEventListener("load", this.setLoaded);
    document.body.appendChild(script);
  },
  methods: {
    ...mapActions('checkout', ['payWithPaypal']),
    ...mapActions('setting', ['getKey']),
    setLoaded: function() {
      this.loaded = true;
      window.paypal
        .Buttons({
          createOrder: (data, actions) => {
            return actions.order.create({
              purchase_units: [
                {
                  description: 'Cart purchase',
                  amount: {
                    currency_code: "USD",
                    value: this.totalPrice
                  }
                }
              ]
            });
          },
          onApprove: async (data, actions) => {
            const order = await actions.order.capture()
            this.paidFor = true
            const user = this.auth.user._id
            const products = this.cart.products
            const address = this.checkout.address
            const amount = this.totalPrice
            const payload = {
              user,
              products,
              data:order,
              address,
              amount
            }
            await this.payWithPaypal(payload)
          },
          onError: err => {
            console.log(err)
          }
        })
        .render(this.$refs.paypal)
    }
  }
}
</script>