<template>
          <v-col cols="" v-if="product.product">
            
            <v-card
            >
                <v-img
                v-if="product.product.avatar"
                height="250"
                :src="setting.settings.images.url+'/products/'+product.product.avatar"
                ></v-img>

                <v-card-title>
                    {{ product.product.name }}
                </v-card-title>

                <v-card-text>
                <v-row
                    align="center"
                    class="mx-0"
                >
                    <v-rating
                    :value="productRating(product.product.reviews)"
                    color="amber"
                    dense
                    half-increments
                    readonly
                    size="14"
                    ></v-rating>

                    <div v-if="product.product.reviews" class="grey--text ml-4">{{ productRating(product.product.reviews) }} ({{ product.product.reviews.length }})</div>
                </v-row>

                <div class="my-4 subtitle-1">
                    <h3 right class="mr-3 primary--text">${{ product.product.price }}</h3>
                </div>
                <div class="my-4 subtitle-1">
                    {{ product.product.category.name }}
                </div>

                <div>
                    {{ product.product.excerpt }}
                </div>
                </v-card-text>
                <v-card-text>
                    <div v-html="product.product.description"></div>
                </v-card-text>

                <v-divider class="mx-4"></v-divider>
                <v-card-actions>
                    <v-btn v-if="product.product.type == 'physical'" @click="addProductToCart" class="mx-auto" color="success" dark>
                        {{ $t('product_page.add_to_cart') }}
                        <v-icon>mdi-cart</v-icon>
                    </v-btn>
                    <v-btn v-if="product.product.type == 'digital'" @click="goToBuy(product._id)" class="mx-auto" color="success" dark>
                        {{ $t('products_page.buy_now') }}
                        <v-icon>mdi-cash-usd</v-icon>
                    </v-btn>
                </v-card-actions>
            </v-card>

            <v-dialog
            v-model="dialog"
            max-width="290"
            >
            <v-card>
                <v-card-title class="headline">{{ $t('product_page.modal_heading') }}</v-card-title>

                <v-card-text>
                    {{ $t('product_page.modal_text') }}
                </v-card-text>

                <v-card-actions>
                <v-spacer></v-spacer>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'register'}"
                >
                    {{ $t('product_page.modal_register') }}
                </v-btn>

                <v-btn
                    color="green darken-1"
                    text
                    link
                    :to="{name:'login'}"
                >
                    {{ $t('product_page.modal_login') }}
                </v-btn>
                </v-card-actions>
            </v-card>
            </v-dialog>
          </v-col>
      <!-- </v-row>
  </v-container> -->
</template>

<script>
import { mapActions, mapState, mapGetters } from 'vuex'
export default {
    data(){
        return {
            dialog:false
        }
    },
    methods: {
        ...mapActions('cart', ['addProduct']),
        addProductToCart(){
            this.addProduct(this.product.product)
        },
        goToBuy(id){
            if(!this.isLoggedIn){
                this.dialog = true
            }else{
                this.$router.push({name:'digitalCheckout', params:{productId:id}})
            }
        }
    },
    computed: {
        ...mapGetters('product', ['productRating', 'productReviewsCount']),
        ...mapState(['product', 'setting']),
        ...mapGetters('auth', ['isLoggedIn'])
    },
}
</script>

