<script>
import { Line } from 'vue-chartjs'
import { mapState } from 'vuex'
export default {
    data(){
        return {
            data:{},
            options:{}
        }
    },
    extends:Line,
    computed:{
      ...mapState(['report']),
    },
    mounted(){
      this.renderChart({
        labels: this.report.records.yearRecords.months,
        datasets: [
          {
            label: this.$t('dashboard_page.annual_sales_record'),
            backgroundColor: '#36b9cc',
            data: this.report.records.yearRecords.sales
          }
        ]
      })
    }
}
</script>

