export default {
    data: () => ({
        rules:{
            required: value => !!value || 'This field is required',
            email: value => /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/.test(value) || 'Please Add Valid Email',
            minLength: value => !!value && value.length >= 8 || 'Password Must Be Atleast 8 Characters',
            image: value => {
                if(value && value.type){
                    return value.type.startsWith('image') || 'Plz upload an image file'
                }else{
                    return true
                }
            },
            imageSize: value => {
                if(value && value.size){
                    return value.size < 2048000 || 'Image size must be less then 2mb' 
                }else{
                    return true
                }
            }
        }
    })
}