<template>
  <v-container>
    <v-row>
      <v-col>
        <v-stepper v-model="e1">
          <v-container>
              <v-stepper-header>
            <v-stepper-step color="dark" :complete="e1 > 1" step="1">{{ $t('checkout_page.delivery_address') }}</v-stepper-step>

            <v-divider></v-divider>

            <v-stepper-step color="dark" step="2">{{ $t('checkout_page.payment') }}</v-stepper-step>
          </v-stepper-header>

          <v-stepper-items>
            <v-stepper-content step="1">
              <Address @changeE1="e1 = 2"/>
            </v-stepper-content>

            <v-stepper-content step="2">
              <Payment/>
            </v-stepper-content>
          </v-stepper-items>
          </v-container>
        </v-stepper>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { mapGetters } from 'vuex'
import Address from '@/components/cart/Address'
import Payment from '@/components/cart/Payment'
export default {
    data(){
        return {
            e1:1
        }
    },
    components:{
      Address,
      Payment
    },
    computed:{
      ...mapGetters('cart', ['hasProduct'])
    },
    created(){
      if(!this.hasProduct){
        this.$router.push({name:'cart'})
      }
    }
}
</script>

