import setErr from '../../utils/ResponseError';
import router from '../../router'
import Axios from 'axios'
export default {
    namespaced:true,
    state:{
        products:[],
        loadingBtn:false
    },
    getters:{
        // get cart length
        cartLength: (state) => {
            return state.products.length
        },
        // get total price of the cart
        totalPrice: (state) => {
            return state.products.reduce((current, next) =>
            current + (next.price * next.quantity), 0);
        },
        // check if cart has product or empty
        hasProduct:(state) => {
            return state.products.length > 0
        },
        // get specific product
        getProduct: state => id => {
            let items = state.products.find(product => product._id == id)
            return items
        },
        // get product index in array of cart products
        productIndex: state => id => {
            let i = state.products.findIndex(product => product._id == id)
            return i
        }
    },
    mutations:{
        // set cart mutaion
        SET_CART: (state , payload) => {
            state.products = payload
        },
        // add product to cart mutation
        ADD_PRODUCT: (state, payload) => {
            // push (add) product in array of products
            state.products.push(payload)
            // set the local storage with updated products
            localStorage.setItem('cart', JSON.stringify(state.products))
        },
        // empty cart mutation
        EMPTY_CART: (state) => {
            // set product to empty array
            state.products = []
            // remove the local storage cart products
            localStorage.removeItem('cart')
        },
        // remove single product mutation
        REMOVE_PRODUCT: (state, index) => {
            // remove single product form products array with splice method
            state.products.splice(index,1)
            // set the local storage with updated products
            localStorage.setItem('cart', JSON.stringify(state.products))
        },
        // loading buttion mutation
        SET_LOADING_BTN: (state, payload) => {
            state.loadingBtn = payload
        },
        // increase quantity of product in products if they already exist
        INCREASE_QTY:(state, payload) => {
            const { item, value } = payload
            // increase quantity of product
            state.products[item].quantity += value
            // set the local storage with updated products
            localStorage.setItem('cart', JSON.stringify(state.products))
        },
        // set local storage products mutaion
        SET_LOCAL_STORAGE_CART: (state, payload) => {
            localStorage.setItem('cart', JSON.stringify(state.products))
        },
        // change quantity of product
        CHANGE_QTY: (state, payload) => {
            const { item, value, type } = payload
            // if type is increase then increment the quantity
            if(type == 'increase'){
                state.products[item].quantity += value
            }else{
                // if type is decrease then decrement the quantity
                state.products[item].quantity -= value
            }
        }
    },
    actions:{
        // add product action
        addProduct: async ({dispatch,commit, getters, rootGetters}, payload) => {
            // set the local btn to true
            commit('SET_LOADING_BTN', true)
            // set the quantity to payload quantity if it exist
            // if payload quantity not exist then set it to 1
            payload.quantity = payload.quantity ? payload.quantity : 1
            // check if product exist and get index of that product
            let item = getters.productIndex(payload._id);
            // check if user logged in
            if(rootGetters['auth/isLoggedIn']){
                // get the auth user id
                let userId = rootGetters['auth/getAuthUser']._id
                try {
                    // send the request to the backend api
                    await Axios.post('/api/cart/'+userId, payload)
                    // set the cart if request is successful
                    await dispatch('setCart')
                    // set the success snackbar alert
                    dispatch('snackbar/setSnackbar', {
                        text:'Product Add To The Cart',
                        type:'success'
                    } , {root:true})
                } catch (error) {
                    // set the error snackbar alert
                    dispatch('snackbar/setSnackbar', {
                        text:setErr(error),
                        type:'error'
                    } , {root:true})
                }
            }else{
                // if user not exist
                // first check if the product exist already in the cart
                if(item != -1){
                    const data = {
                        item,
                        value:payload.quantity ? payload.quantity : 1
                    }
                    // increase the quantity of the product
                    commit('INCREASE_QTY', data)
                    // set cart after increment
                    dispatch('setCart')
                }else{
                    // if product not exist in the cart then add it
                    commit('ADD_PRODUCT', payload)
                }
                // set success snackbar alert
                dispatch('snackbar/setSnackbar', {
                    text:'Product Add To The Cart',
                    type:'success'
                } , {root:true})
            }
            // set loading btn to false after 1s
            setTimeout(() => {
                commit('SET_LOADING_BTN', false)
            }, 1000)
        },
        // empty cart action
        emptyCart: ({commit}) => {
            // empty cart mutation
            commit('EMPTY_CART')
        },
        // remove product action
        removeProduct: async ({dispatch,commit, rootGetters}, payload) => {
            // set loading btn to true
            commit('SET_LOADING_BTN', true)
            const { index, productId } = payload
            // check if user logged in
            if(rootGetters['auth/isLoggedIn']){
                // get the auth user id
                let userId = rootGetters['auth/getAuthUser']._id
                try {
                    // send the request to backend api
                    await Axios.delete('/api/cart/'+productId+'/'+userId)
                    // set cart if the request successful
                    dispatch('setCart')
                    // set success snackbar alert
                    dispatch('snackbar/setSnackbar', {
                        text:'Product Removed From Cart',
                        type:'success'
                    } , {root:true})
                } catch (error) {
                    // set error snackbar alert
                    dispatch('snackbar/setSnackbar', {
                        text:'Something Went Wrong',
                        type:'error'
                    } , {root:true})
                }
            }else{
                // remove product mutation
                commit('REMOVE_PRODUCT', index)
                // set local storage products
                commit('SET_LOCAL_STORAGE_CART')
            }
            // set loading btn to false
            commit('SET_LOADING_BTN', false)
        },
        setCart: async ({dispatch,commit,rootGetters}) => {
            if(rootGetters['auth/isLoggedIn']){
                const userId = rootGetters['auth/getAuthUser']._id
                try {
                    const payload = await Axios.get('/api/cart/'+userId)
                    commit('SET_CART', payload.data.data)
                } catch (error) {
                }
            }else{
                const payload = JSON.parse(localStorage.getItem('cart'))
                if(payload){
                    commit('SET_CART', payload)
                    commit('SET_LOCAL_STORAGE_CART')
                }
            }
        },
        changeQty: async ({dispatch,commit,state,rootGetters}, payload) => {
            const { productId, value, type } = payload
            try {
                if(rootGetters['auth/isLoggedIn']){
                    let userId = rootGetters['auth/getAuthUser']._id
                    let data = {value, type}
                    await Axios.post('/api/cart/'+productId+'/'+userId, data)
                    dispatch('setCart')
                }else{
                    let item = state.products.findIndex(product => product._id == productId)
                    const data = {item, value, type}
                    commit('CHANGE_QTY',data)
                    commit('SET_LOCAL_STORAGE_CART')
                    dispatch('setCart')
                }
            } catch (error) {
                console.log(error.response)
            }
        }
    }
}